import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Person {
  id: string;
  name: string;
  avatarColor: string;
}

export interface BillItem {
  id: string;
  name: string;
  price: number;
  assignedPersonIds: string[];
}

export interface SplitResult {
  person: Person;
  items: { itemName: string; share: number }[];
  subtotal: number;
  tax: number;
  tip: number;
  total: number;
}

import { GoogleGenAI, Type } from "@google/genai";

const getAiClient = () => new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export interface ParsedReceiptItem {
  name: string;
  price: number;
}

export const parseReceiptImage = async (base64Data: string): Promise<ParsedReceiptItem[]> => {
  const ai = getAiClient();

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        {
          inlineData: {
            mimeType: 'image/jpeg',
            data: base64Data.split(',')[1] || base64Data,
          },
        },
        {
          text: "Extract all items and their individual prices from this receipt. Ignore tax, total, or subtotal lines unless they are actual distinct menu items. Return an array of objects."
        }
      ]
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            name: { type: Type.STRING, description: "Name of the item" },
            price: { type: Type.NUMBER, description: "Price of the item" }
          },
          required: ["name", "price"]
        }
      }
    }
  });

  try {
    const data = JSON.parse(response.text || "[]");
    return data;
  } catch (error) {
    console.error("Failed to parse Gemini response", error);
    return [];
  }
};

import React, { useState, useMemo, useCallback } from 'react';
import { Person, BillItem, SplitResult } from './types';
import { AVATAR_COLORS } from './constants';
import PeopleManager from './components/PeopleManager';
import BillManager from './components/BillManager';
import Summary from './components/Summary';
import Header from './components/Header';

const App: React.FC = () => {
  const [people, setPeople] = useState<Person[]>([
    { id: '1', name: 'Me', avatarColor: AVATAR_COLORS[0] }
  ]);
  const [items, setItems] = useState<BillItem[]>([]);
  const [taxPercent, setTaxPercent] = useState<number>(0);
  const [tipPercent, setTipPercent] = useState<number>(15);

  const addPerson = (name: string) => {
    const newPerson: Person = {
      id: crypto.randomUUID(),
      name,
      avatarColor: AVATAR_COLORS[people.length % AVATAR_COLORS.length]
    };
    setPeople([...people, newPerson]);
  };

  const removePerson = (id: string) => {
    if (people.length <= 1) return;
    setPeople(people.filter(p => p.id !== id));
    // Clean up assignments
    setItems(items.map(item => ({
      ...item,
      assignedPersonIds: item.assignedPersonIds.filter(pid => pid !== id)
    })));
  };

  const addItem = (name: string, price: number) => {
    const newItem: BillItem = {
      id: crypto.randomUUID(),
      name,
      price,
      assignedPersonIds: [people[0].id] // Default to first person
    };
    setItems([...items, newItem]);
  };

  const updateItem = (updatedItem: BillItem) => {
    setItems(items.map(item => item.id === updatedItem.id ? updatedItem : item));
  };

  const removeItem = (id: string) => {
    setItems(items.filter(item => item.id !== id));
  };

  const addBulkItems = (newItems: { name: string; price: number }[]) => {
    const itemsToAdd = newItems.map(ni => ({
      id: crypto.randomUUID(),
      name: ni.name,
      price: ni.price,
      assignedPersonIds: [people[0].id]
    }));
    setItems([...items, ...itemsToAdd]);
  };

  const splitResults = useMemo(() => {
    const resultsMap: Record<string, SplitResult> = {};
    people.forEach(p => {
      resultsMap[p.id] = {
        person: p,
        items: [],
        subtotal: 0,
        tax: 0,
        tip: 0,
        total: 0
      };
    });

    let totalSubtotal = 0;
    items.forEach(item => {
      const numPeople = item.assignedPersonIds.length;
      if (numPeople === 0) return;

      const share = item.price / numPeople;
      totalSubtotal += item.price;

      item.assignedPersonIds.forEach(pid => {
        if (resultsMap[pid]) {
          resultsMap[pid].items.push({ itemName: item.name, share });
          resultsMap[pid].subtotal += share;
        }
      });
    });

    const taxAmount = (totalSubtotal * taxPercent) / 100;
    const tipAmount = (totalSubtotal * tipPercent) / 100;

    people.forEach(p => {
      const res = resultsMap[p.id];
      const ratio = totalSubtotal > 0 ? res.subtotal / totalSubtotal : 0;
      res.tax = taxAmount * ratio;
      res.tip = tipAmount * ratio;
      res.total = res.subtotal + res.tax + res.tip;
    });

    return Object.values(resultsMap);
  }, [people, items, taxPercent, tipPercent]);

  return (
    <div className="min-h-screen bg-slate-50 pb-20">
      <Header />

      <main className="max-w-4xl mx-auto px-4 pt-6 space-y-8">
        {/* People Section */}
        <section>
          <PeopleManager 
            people={people} 
            onAdd={addPerson} 
            onRemove={removePerson} 
          />
        </section>

        {/* Items Section */}
        <section>
          <BillManager 
            items={items} 
            people={people}
            onAddItem={addItem} 
            onUpdateItem={updateItem}
            onRemoveItem={removeItem}
            onBulkAdd={addBulkItems}
            taxPercent={taxPercent}
            tipPercent={tipPercent}
            onTaxChange={setTaxPercent}
            onTipChange={setTipPercent}
          />
        </section>

        {/* Results Section */}
        <section>
          <Summary results={splitResults} />
        </section>
      </main>

      {/* Floating Action Bar for Mobile (Optional extra visibility) */}
      <div className="fixed bottom-0 left-0 right-0 bg-white border-t border-slate-200 p-4 md:hidden flex justify-between items-center shadow-lg z-50">
        <div className="text-sm font-medium text-slate-500">Total: <span className="text-indigo-600 font-bold">${splitResults.reduce((acc, r) => acc + r.total, 0).toFixed(2)}</span></div>
        <button 
          onClick={() => window.scrollTo({ top: document.body.scrollHeight, behavior: 'smooth' })}
          className="bg-indigo-600 text-white px-4 py-2 rounded-full text-sm font-semibold shadow-md active:scale-95 transition-transform"
        >
          View Split
        </button>
      </div>
    </div>
  );
};

export default App;

