import React, { useState, useMemo, useEffect } from 'react';
import { Person, BillItem, SplitResult, HistoryEntry } from './types';
import { AVATAR_COLORS } from './constants';
import PeopleManager from './components/PeopleManager';
import BillManager from './components/BillManager';
import Summary from './components/Summary';
import Header from './components/Header';
import History from './components/History';

const App: React.FC = () => {
  const [people, setPeople] = useState<Person[]>([
    { id: '1', name: 'Me', avatarColor: AVATAR_COLORS[0] }
  ]);
  const [items, setItems] = useState<BillItem[]>([]);
  const [history, setHistory] = useState<HistoryEntry[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [showSplitModal, setShowSplitModal] = useState(false);

  // Persistence for history
  useEffect(() => {
    const saved = localStorage.getItem('splitwise_history');
    if (saved) setHistory(JSON.parse(saved));
  }, []);

  const saveToHistory = (results: SplitResult[]) => {
    if (items.length === 0) return;
    const total = items.reduce((acc, item) => acc + item.price, 0);
    const newEntry: HistoryEntry = {
      id: crypto.randomUUID(),
      date: new Date().toLocaleString(),
      title: items.length > 0 ? items[0].name + (items.length > 1 ? '...' : '') : 'Quick Split',
      total,
      results
    };
    const updatedHistory = [newEntry, ...history];
    setHistory(updatedHistory);
    localStorage.setItem('splitwise_history', JSON.stringify(updatedHistory));
  };

  const clearCurrent = () => {
    setItems([]);
    setPeople([{ id: '1', name: 'Me', avatarColor: AVATAR_COLORS[0] }]);
  };

  const addPerson = (name: string) => {
    const newPerson: Person = {
      id: crypto.randomUUID(),
      name,
      avatarColor: AVATAR_COLORS[people.length % AVATAR_COLORS.length]
    };
    setPeople([...people, newPerson]);
  };

  const removePerson = (id: string) => {
    if (people.length <= 1) return;
    setPeople(people.filter(p => p.id !== id));
    setItems(items.map(item => ({
      ...item,
      assignedPersonIds: item.assignedPersonIds.filter(pid => pid !== id)
    })));
  };

  const addItem = (name: string, price: number) => {
    const newItem: BillItem = {
      id: crypto.randomUUID(),
      name,
      price,
      assignedPersonIds: [people[0].id]
    };
    setItems([...items, newItem]);
  };

  const updateItem = (updatedItem: BillItem) => {
    setItems(items.map(item => item.id === updatedItem.id ? updatedItem : item));
  };

  const removeItem = (id: string) => {
    setItems(items.filter(item => item.id !== id));
  };

  const addBulkItems = (newItems: { name: string; price: number }[]) => {
    const itemsToAdd = newItems.map(ni => ({
      id: crypto.randomUUID(),
      name: ni.name,
      price: ni.price,
      assignedPersonIds: [people[0].id]
    }));
    setItems([...items, ...itemsToAdd]);
  };

  const splitResults = useMemo(() => {
    const resultsMap: Record<string, SplitResult> = {};
    people.forEach(p => {
      resultsMap[p.id] = {
        person: p,
        items: [],
        subtotal: 0,
        total: 0
      };
    });

    items.forEach(item => {
      const numPeople = item.assignedPersonIds.length;
      if (numPeople === 0) return;

      const share = item.price / numPeople;

      item.assignedPersonIds.forEach(pid => {
        if (resultsMap[pid]) {
          resultsMap[pid].items.push({ itemName: item.name, share });
          resultsMap[pid].subtotal += share;
          resultsMap[pid].total += share;
        }
      });
    });

    return Object.values(resultsMap);
  }, [people, items]);

  return (
    <div className="min-h-screen bg-slate-50 pb-20">
      <Header onToggleHistory={() => setShowHistory(!showHistory)} />

      <main className="max-w-4xl mx-auto px-4 pt-6 space-y-8">
        {showHistory ? (
          <History 
            history={history} 
            onClose={() => setShowHistory(false)} 
            onClearHistory={() => {
              setHistory([]);
              localStorage.removeItem('splitwise_history');
            }}
          />
        ) : (
          <>
            <section>
              <PeopleManager 
                people={people} 
                onAdd={addPerson} 
                onRemove={removePerson} 
              />
            </section>

            <section>
              <BillManager 
                items={items} 
                people={people}
                onAddItem={addItem} 
                onUpdateItem={updateItem}
                onRemoveItem={removeItem}
                onBulkAdd={addBulkItems}
              />
            </section>

            <section>
              <Summary 
                results={splitResults} 
                totalItems={items.length}
                onSave={() => {
                  saveToHistory(splitResults);
                  alert("Split saved to history!");
                }}
                onClear={clearCurrent}
              />
            </section>
          </>
        )}
      </main>

      {/* Modal for viewing split details with share/export options */}
      {showSplitModal && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
          <div className="bg-white w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">
            <div className="flex justify-between items-center p-6 border-b border-slate-100 bg-white sticky top-0 z-10">
              <h2 className="text-xl font-bold text-slate-800">Split Details</h2>
              <button 
                onClick={() => setShowSplitModal(false)}
                className="w-10 h-10 flex items-center justify-center bg-slate-100 hover:bg-slate-200 text-slate-500 rounded-full transition-colors"
              >
                <i className="fa-solid fa-xmark"></i>
              </button>
            </div>
            <div className="overflow-y-auto flex-1 custom-scrollbar">
              <Summary 
                results={splitResults} 
                totalItems={items.length}
                onSave={() => saveToHistory(splitResults)}
                onClear={clearCurrent}
                isModal
              />
            </div>
          </div>
        </div>
      )}

      {!showHistory && !showSplitModal && (
        <div className="fixed bottom-0 left-0 right-0 bg-white border-t border-slate-200 p-4 md:hidden flex justify-between items-center shadow-lg z-50">
          <div className="text-sm font-medium text-slate-500">
            Total: <span className="text-indigo-600 font-bold">₱{splitResults.reduce((acc, r) => acc + r.total, 0).toLocaleString(undefined, { minimumFractionDigits: 2 })}</span>
          </div>
          <button 
            onClick={() => setShowSplitModal(true)}
            className="bg-indigo-600 text-white px-6 py-2.5 rounded-full text-sm font-bold shadow-lg shadow-indigo-100 active:scale-95 transition-transform flex items-center gap-2"
          >
            <i className="fa-solid fa-expand text-xs"></i>
            View Split
          </button>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useRef } from 'react';
import { SplitResult } from '../types';
import * as htmlToImage from 'html-to-image';

interface Props {
  results: SplitResult[];
  totalItems: number;
  onSave: () => void;
  onClear: () => void;
  isModal?: boolean;
}

const Summary: React.FC<Props> = ({ results, totalItems, onSave, onClear, isModal = false }) => {
  const exportRef = useRef<HTMLDivElement>(null);
  const grandTotal = results.reduce((acc, r) => acc + r.total, 0);

  const handleExportImage = async () => {
    if (!exportRef.current) return;

    try {
      // Small delay to ensure any fonts/icons are ready
      const dataUrl = await htmlToImage.toPng(exportRef.current, {
        quality: 1,
        backgroundColor: '#f8fafc', // Same as app background
        pixelRatio: 2 // High quality
      });

      const link = document.createElement('a');
      link.download = `split-bill-${new Date().getTime()}.png`;
      link.href = dataUrl;
      link.click();
    } catch (err) {
      console.error('Failed to export image', err);
      alert('Could not generate image. Please try taking a screenshot instead.');
    }
  };

  const handleShare = async () => {
    if (!exportRef.current) return;

    try {
      const dataUrl = await htmlToImage.toPng(exportRef.current, {
        backgroundColor: '#f8fafc',
        pixelRatio: 2
      });

      const response = await fetch(dataUrl);
      const blob = await response.blob();
      const file = new File([blob], 'bill-split.png', { type: 'image/png' });

      if (navigator.share && navigator.canShare && navigator.canShare({ files: [file] })) {
        await navigator.share({
          files: [file],
          title: 'Bill Split Overview',
          text: 'Here is the breakdown for our bill.'
        });
      } else {
        // Fallback to download
        handleExportImage();
      }
    } catch (err) {
      console.error('Share failed', err);
      handleExportImage();
    }
  };

  if (results.length === 0 || results.every(r => r.total === 0)) {
    return (
      <div className={`${isModal ? '' : 'bg-white rounded-2xl border border-slate-100 shadow-sm'} p-6 text-center py-12 text-slate-400 italic`}>
        Add items and assign them to see the split!
      </div>
    );
  }

  return (
    <div className={`${isModal ? '' : 'bg-white rounded-2xl border border-slate-100 shadow-sm'} p-6`}>
      <div className="flex items-center justify-between mb-8">
        {!isModal && (
          <div className="flex items-center gap-2">
            <i className="fa-solid fa-chart-pie text-indigo-500"></i>
            <h2 className="text-lg font-semibold text-slate-800">Split Overview</h2>
          </div>
