            const paidPeople = entry.results.filter(r => r.isPaid).length;
            const isFullyPaid = totalPeople > 0 && paidPeople === totalPeople;
            const isPartiallyPaid = paidPeople > 0 && paidPeople < totalPeople;

            return (
              <div 
