import React from 'react';
import { HistoryEntry } from '../types';

interface Props {
  history: HistoryEntry[];
  onClose: () => void;
  onClearHistory: () => void;
  onTogglePaid: (billId: string, personId: string) => void;
}

const SavedBills: React.FC<Props> = ({ history, onClose, onClearHistory, onTogglePaid }) => {
  return (
    <div className="bg-white dark:bg-slate-900 rounded-2xl p-6 shadow-sm border border-slate-100 dark:border-slate-800 transition-colors">
      <div className="flex items-center justify-between mb-8">
        <div className="flex items-center gap-2">
          <i className="fa-solid fa-bookmark text-indigo-500"></i>
          <h2 className="text-lg font-semibold text-slate-800 dark:text-slate-100">Saved Bills</h2>
        </div>
        <div className="flex gap-4">
          <button 
            onClick={onClearHistory}
            className="text-xs font-bold text-rose-500 hover:text-rose-600 transition-colors"
          >
            Clear All
          </button>
          <button 
            onClick={onClose}
            className="text-slate-400 dark:text-slate-500 hover:text-slate-600 dark:hover:text-slate-400 transition-colors"
          >
            <i className="fa-solid fa-xmark text-lg"></i>
          </button>
        </div>
      </div>

      {history.length === 0 ? (
        <div className="text-center py-16">
          <div className="bg-slate-50 dark:bg-slate-800 w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-4">
            <i className="fa-solid fa-ghost text-slate-300 dark:text-slate-600 text-2xl"></i>
          </div>
          <p className="text-slate-400 dark:text-slate-600 italic">No saved bills yet. Start splitting!</p>
        </div>
      ) : (
        <div className="space-y-4">
          {history.map((entry) => {
            const totalPeople = entry.results.length;
            const paidPeople = entry.results.filter(r => r.isPaid).length;
            const isFullyPaid = totalPeople > 0 && paidPeople === totalPeople;
            const isPartiallyPaid = paidPeople > 0 && paidPeople < totalPeople;

            return (
              <div 
                key={entry.id} 
                className={`p-4 bg-slate-50 dark:bg-slate-800/50 rounded-2xl border transition-all ${isFullyPaid ? 'border-emerald-200 dark:border-emerald-900/30' : 'border-slate-100 dark:border-slate-800'} hover:border-indigo-200 dark:hover:border-indigo-700`}
              >
                <div className="flex justify-between items-start mb-4">
                  <div className="flex items-start gap-3">
                    <div className={`mt-1.5 w-2.5 h-2.5 rounded-full ${isFullyPaid ? 'bg-emerald-500' : isPartiallyPaid ? 'bg-amber-500' : 'bg-slate-300'} shadow-sm`}></div>
                    <div>
                      <h3 className="font-bold text-slate-800 dark:text-slate-200 leading-tight">{entry.title}</h3>
                      <p className="text-[10px] text-slate-400 dark:text-slate-500 font-bold uppercase tracking-wider mt-0.5">{entry.date}</p>
                    </div>
                  </div>
                  <div className="text-right">
                    <p className={`text-lg font-black transition-colors ${isFullyPaid ? 'text-emerald-600 dark:text-emerald-400' : 'text-indigo-600 dark:text-indigo-400'}`}>
                      ₱{entry.total.toLocaleString(undefined, { minimumFractionDigits: 2 })}
                    </p>
                    <p className={`text-[9px] font-black uppercase mt-0.5 ${isFullyPaid ? 'text-emerald-500' : 'text-slate-400'}`}>
                      {paidPeople}/{totalPeople} Paid
                    </p>
                  </div>
                </div>

                <div className="flex flex-wrap gap-2">
                  {entry.results.map((res) => (
                    <button 
                      key={res.person.id} 
                      onClick={() => onTogglePaid(entry.id, res.person.id)}
                      className={`flex items-center gap-1.5 px-2.5 py-1 rounded-full border text-[10px] font-bold transition-all active:scale-95 ${res.isPaid ? 'bg-emerald-50 dark:bg-emerald-900/20 border-emerald-100 dark:border-emerald-900/30 text-emerald-600' : 'bg-white dark:bg-slate-900 border-slate-200 dark:border-slate-700 text-slate-600 dark:text-slate-400'}`}
                      title={`Click to mark ${res.person.name} as ${res.isPaid ? 'unpaid' : 'paid'}`}
                    >
                      <div className={`w-3 h-3 rounded-full flex items-center justify-center text-[6px] text-white ${res.isPaid ? 'bg-emerald-500' : res.person.avatarColor}`}>
                        {res.isPaid && <i className="fa-solid fa-check"></i>}
                      </div>
                      {res.person.name}
                    </button>
                  ))}
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
};

export default SavedBills;

import React, { useState, useMemo, useEffect } from 'react';
import { Person, BillItem, SplitResult, HistoryEntry } from './types';
import { AVATAR_COLORS } from './constants';
import PeopleManager from './components/PeopleManager';
import BillManager from './components/BillManager';
import Summary from './components/Summary';
import Header from './components/Header';
import SavedBills from './components/SavedBills';

const App: React.FC = () => {
  const [people, setPeople] = useState<Person[]>([
    { id: '1', name: 'Me', avatarColor: AVATAR_COLORS[0] }
  ]);
  const [items, setItems] = useState<BillItem[]>([]);
  const [history, setHistory] = useState<HistoryEntry[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [showSplitModal, setShowSplitModal] = useState(false);
  const [paidStatus, setPaidStatus] = useState<Record<string, boolean>>({});
  const [darkMode, setDarkMode] = useState(() => {
    return localStorage.getItem('splitwise_theme') === 'dark';
  });

  // Theme effect
  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('splitwise_theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('splitwise_theme', 'light');
    }
  }, [darkMode]);

  // Persistence for history
  useEffect(() => {
    const saved = localStorage.getItem('splitwise_history');
    if (saved) setHistory(JSON.parse(saved));
  }, []);

  const toggleTheme = () => setDarkMode(!darkMode);

  const togglePersonPaid = (personId: string) => {
    setPaidStatus(prev => ({
      ...prev,
      [personId]: !prev[personId]
    }));
  };

  const togglePaidInHistory = (billId: string, personId: string) => {
    const updatedHistory = history.map(entry => {
      if (entry.id === billId) {
        return {
          ...entry,
          results: entry.results.map(res => 
            res.person.id === personId ? { ...res, isPaid: !res.isPaid } : res
          )
        };
      }
      return entry;
    });
    setHistory(updatedHistory);
    localStorage.setItem('splitwise_history', JSON.stringify(updatedHistory));
  };

  const deleteBillFromHistory = (billId: string) => {
    if (confirm("Are you sure you want to delete this bill?")) {
      const updatedHistory = history.filter(entry => entry.id !== billId);
      setHistory(updatedHistory);
      localStorage.setItem('splitwise_history', JSON.stringify(updatedHistory));
    }
  };

  const saveToHistory = (results: SplitResult[]) => {
    if (items.length === 0) return;
    const total = items.reduce((acc, item) => acc + item.price, 0);
    const newEntry: HistoryEntry = {
      id: crypto.randomUUID(),
      date: new Date().toLocaleString(),
      title: items.length > 0 ? items[0].name + (items.length > 1 ? '...' : '') : 'Quick Split',
      total,
      results
    };
    const updatedHistory = [newEntry, ...history];
    setHistory(updatedHistory);
    localStorage.setItem('splitwise_history', JSON.stringify(updatedHistory));
  };

  const clearCurrent = () => {
    setItems([]);
    setPeople([{ id: '1', name: 'Me', avatarColor: AVATAR_COLORS[0] }]);
    setPaidStatus({});
  };

  const addPerson = (name: string) => {
    const newPerson: Person = {
      id: crypto.randomUUID(),
      name,
      avatarColor: AVATAR_COLORS[people.length % AVATAR_COLORS.length]
    };
    setPeople([...people, newPerson]);
  };

  const removePerson = (id: string) => {
    if (people.length <= 1) return;
    setPeople(people.filter(p => p.id !== id));
    setItems(items.map(item => ({
      ...item,
      assignedPersonIds: item.assignedPersonIds.filter(pid => pid !== id)
    })));
    const newPaidStatus = { ...paidStatus };
    delete newPaidStatus[id];
    setPaidStatus(newPaidStatus);
  };

  const addItem = (name: string, price: number) => {
    const newItem: BillItem = {
      id: crypto.randomUUID(),
      name,
      price,
      assignedPersonIds: [people[0].id]
    };
    setItems([...items, newItem]);
  };

  const updateItem = (updatedItem: BillItem) => {
    setItems(items.map(item => item.id === updatedItem.id ? updatedItem : item));
  };

  const removeItem = (id: string) => {
    setItems(items.filter(item => item.id !== id));
  };

  const addBulkItems = (newItems: { name: string; price: number }[]) => {
    const itemsToAdd = newItems.map(ni => ({
      id: crypto.randomUUID(),
      name: ni.name,
      price: ni.price,
      assignedPersonIds: [people[0].id]
    }));
    setItems([...items, ...itemsToAdd]);
  };

  const splitResults = useMemo(() => {
    const resultsMap: Record<string, SplitResult> = {};
    people.forEach(p => {
      resultsMap[p.id] = {
        person: p,
        items: [],
        subtotal: 0,
        total: 0,
        isPaid: !!paidStatus[p.id]
      };
    });

    items.forEach(item => {
      const numPeople = item.assignedPersonIds.length;
      if (numPeople === 0) return;

      const share = item.price / numPeople;

      item.assignedPersonIds.forEach(pid => {
        if (resultsMap[pid]) {
          resultsMap[pid].items.push({ itemName: item.name, share });
          resultsMap[pid].subtotal += share;
          resultsMap[pid].total += share;
        }
      });
    });

    return Object.values(resultsMap);
  }, [people, items, paidStatus]);

  return (
    <div className="min-h-screen bg-slate-50 dark:bg-slate-950 transition-colors duration-300 pb-20">
      <Header 
        onToggleHistory={() => setShowHistory(!showHistory)} 
        onToggleTheme={toggleTheme}
        darkMode={darkMode}
      />

      <main className="max-w-4xl mx-auto px-4 pt-6 space-y-8">
        {showHistory ? (
          <SavedBills 
            history={history} 
            onClose={() => setShowHistory(false)} 
            onTogglePaid={togglePaidInHistory}
            onDeleteBill={deleteBillFromHistory}
            onClearHistory={() => {
              if (confirm("Are you sure you want to clear all saved bills?")) {
                setHistory([]);
                localStorage.removeItem('splitwise_history');
              }
            }}
          />
        ) : (
          <>
            <section>
              <PeopleManager 
                people={people} 
                onAdd={addPerson} 
                onRemove={removePerson} 
              />
            </section>

            <section>
              <BillManager 
                items={items} 
                people={people}
                onAddItem={addItem} 
                onUpdateItem={updateItem}
                onRemoveItem={removeItem}
                onBulkAdd={addBulkItems}
              />
            </section>

            <section>
              <Summary 
                results={splitResults} 
                totalItems={items.length}
                onTogglePaid={togglePersonPaid}
                onSave={() => {
                  saveToHistory(splitResults);
                  alert("Bill saved successfully!");
                }}
                onClear={clearCurrent}
              />
            </section>
          </>
        )}
      </main>

      {/* Modal for viewing split details */}
      {showSplitModal && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
          <div className="bg-white dark:bg-slate-900 w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">
            <div className="flex justify-between items-center p-6 border-b border-slate-100 dark:border-slate-800 bg-white dark:bg-slate-900 sticky top-0 z-10">
              <h2 className="text-xl font-bold text-slate-800 dark:text-slate-100">Split Details</h2>
              <button 
                onClick={() => setShowSplitModal(false)}
                className="w-10 h-10 flex items-center justify-center bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 dark:hover:bg-slate-700 text-slate-500 dark:text-slate-400 rounded-full transition-colors"
              >
                <i className="fa-solid fa-xmark"></i>
              </button>
            </div>
            <div className="overflow-y-auto flex-1 custom-scrollbar">
              <Summary 
                results={splitResults} 
                totalItems={items.length}
                onTogglePaid={togglePersonPaid}
                onSave={() => saveToHistory(splitResults)}
                onClear={clearCurrent}
                isModal
              />
            </div>
          </div>
        </div>
      )}

      {!showHistory && !showSplitModal && (
        <div className="fixed bottom-0 left-0 right-0 bg-white dark:bg-slate-900 border-t border-slate-200 dark:border-slate-800 p-4 md:hidden flex justify-between items-center shadow-lg z-50 transition-colors">
          <div className="text-sm font-medium text-slate-500 dark:text-slate-400">
            Total: <span className="text-indigo-600 dark:text-indigo-400 font-bold">₱{splitResults.reduce((acc, r) => acc + r.total, 0).toLocaleString(undefined, { minimumFractionDigits: 2 })}</span>
          </div>
          <button 
            onClick={() => setShowSplitModal(true)}
            className="bg-indigo-600 dark:bg-indigo-500 text-white px-6 py-2.5 rounded-full text-sm font-bold shadow-lg shadow-indigo-100 dark:shadow-none active:scale-95 transition-transform flex items-center gap-2"
          >
            <i className="fa-solid fa-expand text-xs"></i>
            View Split
          </button>
        </div>
      )}
    </div>
  );
};

export default App;

import React from 'react';
import { HistoryEntry } from '../types';

interface Props {
  history: HistoryEntry[];
  onClose: () => void;
