import { GoogleGenAI, Type } from "@google/genai";

export interface ParsedReceiptItem {
  name: string;
  price: number;
}

export const parseReceiptImage = async (base64Data: string): Promise<ParsedReceiptItem[]> => {
  // Always create a fresh instance with the current process.env.API_KEY
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  // Extract base64 and mime type correctly
  const mimeMatch = base64Data.match(/^data:(image\/[a-zA-Z+]+);base64,/);
  const mimeType = mimeMatch ? mimeMatch[1] : 'image/jpeg';
  const cleanBase64 = base64Data.replace(/^data:image\/[a-zA-Z+]+;base64,/, "");

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: mimeType,
              data: cleanBase64,
            },
          },
          {
            text: "You are a professional receipt digitizer. Scan this image and extract every single purchased item as a separate object. Extract only the base price for each item. Ignore tax, tips, or service fees unless they are listed as separate specific items you want to keep. Return ONLY a raw JSON array of objects with 'name' (string) and 'price' (number) keys. Do not include markdown formatting or explanation text."
          }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              name: { type: Type.STRING, description: "Item description" },
              price: { type: Type.NUMBER, description: "Item cost as a number" }
            },
            required: ["name", "price"]
          }
        }
      }
    });

    const text = response.text;
    if (!text) return [];

    // Attempt to clean the text in case the model ignored 'no markdown' instructions
    let jsonStr = text.trim();
    if (jsonStr.startsWith("```")) {
      jsonStr = jsonStr.replace(/^```[a-z]*\n/, "").replace(/\n```$/, "");
    }

    return JSON.parse(jsonStr);
  } catch (error) {
    console.error("Gemini Scanning Error Details:", error);
    throw error;
  }
};

import React, { useState, useRef } from 'react';
import { BillItem, Person } from '../types';
import { parseReceiptImage } from '../services/geminiService';

interface Props {
  items: BillItem[];
  people: Person[];
  billTitle: string;
  setBillTitle: (title: string) => void;
  onAddItem: (name: string, price: number) => void;
  onUpdateItem: (item: BillItem) => void;
  onRemoveItem: (id: string) => void;
  onBulkAdd: (items: { name: string; price: number }[]) => void;
  onClearAll: () => void;
}

const BillManager: React.FC<Props> = ({ 
  items, 
  people, 
  billTitle,
  setBillTitle,
  onAddItem, 
  onUpdateItem, 
  onRemoveItem, 
  onBulkAdd,
  onClearAll
}) => {
  const [itemName, setItemName] = useState('');
  const [itemPrice, setItemPrice] = useState('');
  const [isScanning, setIsScanning] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleAddItem = (e: React.FormEvent) => {
    e.preventDefault();
    const price = parseFloat(itemPrice);
    if (itemName.trim() && !isNaN(price)) {
      onAddItem(itemName.trim(), price);
      setItemName('');
      setItemPrice('');
    }
  };

  const togglePersonOnItem = (item: BillItem, personId: string) => {
    const isAssigned = item.assignedPersonIds.includes(personId);
    let newIds: string[];
    if (isAssigned) {
      newIds = item.assignedPersonIds.filter(id => id !== personId);
    } else {
      newIds = [...item.assignedPersonIds, personId];
    }
    onUpdateItem({ ...item, assignedPersonIds: newIds });
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsScanning(true);
    const reader = new FileReader();
    reader.onload = async (event) => {
      const base64 = event.target?.result as string;
      try {
        const parsedItems = await parseReceiptImage(base64);
        onBulkAdd(parsedItems);
        if (parsedItems.length > 0) {
          alert(`Success! Found ${parsedItems.length} items.`);
        }
      } catch (err) {
        console.error(err);
        alert("Extraction failed. Please try a clearer photo or enter manually.");
      } finally {
        setIsScanning(false);
        if (fileInputRef.current) fileInputRef.current.value = '';
      }
    };
    reader.readAsDataURL(file);
  };

  const totalBill = items.reduce((acc, item) => acc + item.price, 0);

  return (
