              : 'bg-indigo-600 text-white hover:bg-indigo-700 shadow-lg shadow-indigo-100 dark:shadow-none'
          }`}
        >
          {isScanning ? (
            <><i className="fa-solid fa-circle-notch animate-spin"></i> Processing...</>
          ) : (
            <><i className="fa-solid fa-camera"></i> Quick Scan</>
          )}
        </button>
        <input 
          type="file" 
          ref={fileInputRef} 
          className="hidden" 
          accept="image/*" 
          onChange={handleFileUpload}
        />
      </div>

      <div className="space-y-6">
        {/* Bill Metadata - The requested "Bill name on top" section */}
        <div className="bg-slate-50 dark:bg-slate-800/40 p-5 rounded-2xl border-2 border-slate-100 dark:border-slate-800 transition-all focus-within:border-indigo-500/30">
