                            ${active 
                              ? `${person.avatarColor.replace('bg-', 'text-')} bg-white dark:bg-slate-900 border-current shadow-sm` 
                              : 'bg-slate-50 dark:bg-slate-800/50 text-slate-400 dark:text-slate-600 border-transparent'
