  };

  const spin = () => {
    if (isSpinning) return;

    setIsSpinning(true);
    setShowResult(false);
    setWinner(null);

    const extraSpins = 5 + Math.random() * 5;
    const newRotation = rotation + (extraSpins * 360) + Math.random() * 360;
    setRotation(newRotation);

    setTimeout(() => {
      setIsSpinning(false);
      // Calculate winner based on final rotation
      const normalizedRotation = (newRotation % 360);
      const degreesPerPerson = 360 / people.length;
      // The pointer is at the top (0 deg). 
      // The wheel rotates clockwise, so we subtract from 360.
      const winningIndex = Math.floor(((360 - (normalizedRotation % 360)) % 360) / degreesPerPerson);
      setWinner(people[winningIndex]);
      setShowResult(true);
    }, 4000);
  };

  // Generate the conic gradient for the wheel
  const wheelStyle = useMemo(() => {
    const segmentDegree = 360 / people.length;
    const gradientParts = people.map((p, i) => {
      const color = colorMap[p.avatarColor] || '#cbd5e1';
      return `${color} ${i * segmentDegree}deg ${(i + 1) * segmentDegree}deg`;
    });

    return {
      background: `conic-gradient(${gradientParts.join(', ')})`,
      transform: `rotate(${rotation}deg)`,
      transition: isSpinning ? 'transform 4s cubic-bezier(0.15, 0, 0.15, 1)' : 'none'
    };
  }, [people, rotation, isSpinning]);

  return (
    <div className="fixed inset-0 z-[70] flex items-center justify-center p-4 bg-slate-950/80 backdrop-blur-md">
      <div className="bg-white dark:bg-slate-900 w-full max-w-md rounded-[2.5rem] shadow-2xl p-8 flex flex-col items-center relative overflow-hidden">
        {/* Close Button */}
        <button 
          onClick={onClose}
          className="absolute top-6 right-6 w-10 h-10 flex items-center justify-center bg-slate-100 dark:bg-slate-800 rounded-full text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 transition-colors z-10"
        >
          <i className="fa-solid fa-xmark"></i>
        </button>

        <div className="text-center mb-8">
          <h2 className="text-2xl font-black text-slate-900 dark:text-slate-50 tracking-tight">Bill Roulette</h2>
          <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mt-1">One person pays it all!</p>
        </div>

        {/* The Wheel UI */}
        <div className="relative w-64 h-64 mb-10 group">
          {/* Pointer */}
          <div className="absolute top-0 left-1/2 -translate-x-1/2 -translate-y-1/2 z-20 w-8 h-10 drop-shadow-lg">
            <div className="w-full h-full bg-slate-900 dark:bg-white clip-triangle flex items-end justify-center pb-1">
               <div className="w-1 h-1 bg-rose-500 rounded-full animate-pulse"></div>
            </div>
          </div>

          {/* Center Pin */}
          <div className="absolute inset-0 m-auto w-12 h-12 bg-white dark:bg-slate-900 rounded-full shadow-xl z-20 border-4 border-slate-100 dark:border-slate-800 flex items-center justify-center">
            <i className="fa-solid fa-mug-hot text-indigo-500 text-sm"></i>
          </div>

          {/* Actual Rotating Wheel */}
          <div 
            className="w-full h-full rounded-full border-8 border-slate-100 dark:border-slate-800 shadow-inner overflow-hidden relative"
            style={wheelStyle}
          >
            {/* Person Initials on Wheel */}
            {people.map((p, i) => {
              const segmentDegree = 360 / people.length;
              const rotation = i * segmentDegree + segmentDegree / 2;
              return (
                <div 
                  key={p.id}
                  className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-full h-full text-center"
                  style={{ transform: `rotate(${rotation}deg)` }}
                >
                   <span className="inline-block mt-4 font-black text-white text-lg drop-shadow-md">
                    {p.name.charAt(0).toUpperCase()}
                   </span>
                </div>
              );
            })}
          </div>

          {/* Decorative Outer Ring */}
          <div className="absolute -inset-4 border-4 border-dashed border-slate-200 dark:border-slate-800 rounded-full animate-[spin_20s_linear_infinite] opacity-30"></div>
        </div>

        {/* Interaction Area */}
        <div className="w-full text-center space-y-6">
          {!showResult ? (
            <button
              onClick={spin}
              disabled={isSpinning}
              className={`w-full py-4 rounded-2xl font-black text-white shadow-xl transition-all active:scale-95 ${
                isSpinning ? 'bg-slate-300 dark:bg-slate-700 cursor-not-allowed' : 'bg-indigo-600 hover:bg-indigo-700'
              }`}
            >
              {isSpinning ? 'LUCK IS DECIDING...' : 'SPIN THE WHEEL'}
            </button>
          ) : (
            <div className="animate-[bounce_0.5s_ease-out]">
              <div className="inline-flex items-center gap-4 bg-emerald-50 dark:bg-emerald-950/30 border border-emerald-100 dark:border-emerald-900/50 p-6 rounded-3xl w-full mb-6">
                <div className={`w-16 h-16 rounded-full ${winner?.avatarColor} flex items-center justify-center text-2xl text-white font-black shadow-lg animate-pulse`}>
                  {winner?.name.charAt(0).toUpperCase()}
                </div>
                <div className="text-left">
                  <p className="text-[10px] font-black uppercase tracking-[0.2em] text-emerald-600 dark:text-emerald-400">The Winner</p>
                  <h3 className="text-2xl font-black text-slate-900 dark:text-slate-50">{winner?.name}</h3>
                  <p className="text-xs text-slate-500 font-medium italic">Better luck next time!</p>
                </div>
              </div>

              <div className="flex gap-3">
                <button
                  onClick={spin}
                  className="flex-1 py-3 bg-slate-100 dark:bg-slate-800 text-slate-700 dark:text-slate-200 rounded-xl font-bold text-sm hover:bg-slate-200 dark:hover:bg-slate-700 transition-colors"
                >
                  Spin Again
                </button>
                <button
                  onClick={onClose}
                  className="flex-1 py-3 bg-indigo-600 text-white rounded-xl font-bold text-sm hover:bg-indigo-700 transition-colors shadow-lg shadow-indigo-100 dark:shadow-none"
                >
                  Got it
                </button>
              </div>
            </div>
          )}
        </div>

        {/* Background Confetti Logic (Visual Only) */}
        {showResult && (
          <div className="absolute inset-0 pointer-events-none overflow-hidden">
             {[...Array(20)].map((_, i) => (
               <div 
                key={i}
                className="absolute w-2 h-2 rounded-full animate-confetti"
                style={{
                  left: `${Math.random() * 100}%`,
                  backgroundColor: Object.values(colorMap)[Math.floor(Math.random() * 8)],
                  animationDelay: `${Math.random() * 2}s`
                }}
               />
             ))}
          </div>
        )}
      </div>

      <style dangerouslySetInnerHTML={{ __html: `
        .clip-triangle {
          clip-path: polygon(50% 100%, 0 0, 100% 0);
        }
        @keyframes confetti {
          0% { transform: translateY(-20px) rotate(0deg); opacity: 1; }
          100% { transform: translateY(500px) rotate(720deg); opacity: 0; }
        }
        .animate-confetti {
          animation: confetti 2s ease-out forwards;
        }
      `}} />
    </div>
  );
};

export default Roulette;

import React, { useState, useMemo, useEffect } from 'react';
import { Person, BillItem, SplitResult, HistoryEntry } from './types';
import { AVATAR_COLORS } from './constants';
import PeopleManager from './components/PeopleManager';
import BillManager from './components/BillManager';
import Summary from './components/Summary';
import Header from './components/Header';
import SavedBills from './components/SavedBills';
import Onboarding from './components/Onboarding';
import Roulette from './components/Roulette';

const App: React.FC = () => {
  // Initialize state from LocalStorage or defaults
  const [people, setPeople] = useState<Person[]>(() => {
    const saved = localStorage.getItem('splitwise_people');
    return saved ? JSON.parse(saved) : [{ id: '1', name: 'Me', avatarColor: AVATAR_COLORS[0] }];
  });

  const [items, setItems] = useState<BillItem[]>(() => {
    const saved = localStorage.getItem('splitwise_items');
    return saved ? JSON.parse(saved) : [];
  });

  const [billTitle, setBillTitle] = useState(() => {
    return localStorage.getItem('splitwise_bill_title') || '';
  });

  const [paidStatus, setPaidStatus] = useState<Record<string, boolean>>(() => {
    const saved = localStorage.getItem('splitwise_paid_status');
    return saved ? JSON.parse(saved) : {};
  });

  const [history, setHistory] = useState<HistoryEntry[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [showSplitModal, setShowSplitModal] = useState(false);
  const [showRoulette, setShowRoulette] = useState(false);
  const [viewingHistoryEntry, setViewingHistoryEntry] = useState<HistoryEntry | null>(null);
  const [showOnboarding, setShowOnboarding] = useState(() => {
    return localStorage.getItem('bayad_buddy_onboarded') !== 'true';
  });

  const [darkMode, setDarkMode] = useState(() => {
    return localStorage.getItem('splitwise_theme') === 'dark';
  });

  // Sync state to LocalStorage
  useEffect(() => {
    localStorage.setItem('splitwise_people', JSON.stringify(people));
  }, [people]);

  useEffect(() => {
    localStorage.setItem('splitwise_items', JSON.stringify(items));
  }, [items]);

  useEffect(() => {
    localStorage.setItem('splitwise_bill_title', billTitle);
  }, [billTitle]);

  useEffect(() => {
    localStorage.setItem('splitwise_paid_status', JSON.stringify(paidStatus));
  }, [paidStatus]);

  // Theme effect
  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('splitwise_theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('splitwise_theme', 'light');
    }
  }, [darkMode]);

  // Persistence for history
  useEffect(() => {
    const saved = localStorage.getItem('splitwise_history');
    if (saved) {
      try {
        setHistory(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to load history", e);
      }
    }
  }, []);

  const toggleTheme = () => setDarkMode(!darkMode);

  const togglePersonPaid = (personId: string) => {
    setPaidStatus(prev => ({
      ...prev,
      [personId]: !prev[personId]
    }));
  };

  const togglePaidInHistory = (billId: string, personId: string) => {
    const updatedHistory = history.map(entry => {
      if (entry.id === billId) {
        const updatedEntry = {
          ...entry,
          results: entry.results.map(res => 
            res.person.id === personId ? { ...res, isPaid: !res.isPaid } : res
          )
        };
        if (viewingHistoryEntry?.id === billId) {
          setViewingHistoryEntry(updatedEntry);
        }
        return updatedEntry;
      }
      return entry;
    });
    setHistory(updatedHistory);
    localStorage.setItem('splitwise_history', JSON.stringify(updatedHistory));
  };

  const removeBillFromHistory = (billId: string) => {
    const updatedHistory = history.filter(entry => entry.id !== billId);
    setHistory(updatedHistory);
    localStorage.setItem('splitwise_history', JSON.stringify(updatedHistory));
  };

  const saveToHistory = (results: SplitResult[]) => {
    if (items.length === 0) return;

    const generateId = () => {
      try {
        return crypto.randomUUID();
      } catch (e) {
        return Math.random().toString(36).substring(2, 15) + Date.now().toString(36);
      }
    };

    const total = items.reduce((acc, item) => acc + item.price, 0);
    const newEntry: HistoryEntry = {
      id: generateId(),
      date: new Date().toLocaleString(),
      title: billTitle.trim() || (items.length > 0 ? items[0].name + (items.length > 1 ? '...' : '') : 'Quick Split'),
      total,
      results: JSON.parse(JSON.stringify(results)) 
    };

    const updatedHistory = [newEntry, ...history];
    setHistory(updatedHistory);
    localStorage.setItem('splitwise_history', JSON.stringify(updatedHistory));
  };

  const clearCurrent = () => {
    if (window.confirm("Clear all items and people?")) {
      setItems([]);
      setBillTitle('');
      setPeople([{ id: '1', name: 'Me', avatarColor: AVATAR_COLORS[0] }]);
      setPaidStatus({});
      // Ensure LocalStorage is also cleaned up
      localStorage.removeItem('splitwise_items');
      localStorage.removeItem('splitwise_bill_title');
      localStorage.removeItem('splitwise_people');
      localStorage.removeItem('splitwise_paid_status');
    }
  };

  const addPerson = (name: string) => {
    const newPerson: Person = {
      id: Math.random().toString(36).substring(2, 9),
      name,
      avatarColor: AVATAR_COLORS[people.length % AVATAR_COLORS.length]
    };
    setPeople([...people, newPerson]);
  };

  const removePerson = (id: string) => {
    if (people.length <= 1) return;
    setPeople(people.filter(p => p.id !== id));
    setItems(items.map(item => ({
      ...item,
      assignedPersonIds: item.assignedPersonIds.filter(pid => pid !== id)
    })));
    const newPaidStatus = { ...paidStatus };
    delete newPaidStatus[id];
    setPaidStatus(newPaidStatus);
  };

  const addItem = (name: string, price: number) => {
    const newItem: BillItem = {
      id: Math.random().toString(36).substring(2, 9),
      name,
      price,
      assignedPersonIds: people.length > 0 ? [people[0].id] : []
    };
    setItems([...items, newItem]);
  };

  const updateItem = (updatedItem: BillItem) => {
    setItems(items.map(item => item.id === updatedItem.id ? updatedItem : item));
  };

  const removeItem = (id: string) => {
    setItems(items.filter(item => item.id !== id));
  };

  const finishOnboarding = () => {
    localStorage.setItem('bayad_buddy_onboarded', 'true');
    setShowOnboarding(false);
  };

  const splitResults = useMemo(() => {
    const resultsMap: Record<string, SplitResult> = {};
    people.forEach(p => {
      resultsMap[p.id] = {
        person: p,
        items: [],
        subtotal: 0,
        total: 0,
        isPaid: !!paidStatus[p.id]
      };
    });

    items.forEach(item => {
      const numPeople = item.assignedPersonIds.length;
      if (numPeople === 0) return;

      const share = item.price / numPeople;

      item.assignedPersonIds.forEach(pid => {
        if (resultsMap[pid]) {
          resultsMap[pid].items.push({ itemName: item.name, share });
          resultsMap[pid].subtotal += share;
          resultsMap[pid].total += share;
        }
      });
    });

    return Object.values(resultsMap);
  }, [people, items, paidStatus]);

  return (
    <div className="min-h-screen bg-slate-50 dark:bg-slate-950 transition-colors duration-300 pb-20">
      {showOnboarding && <Onboarding onFinish={finishOnboarding} />}
      {showRoulette && <Roulette people={people} onClose={() => setShowRoulette(false)} />}

      <Header 
        onToggleHistory={() => setShowHistory(!showHistory)} 
        onToggleTheme={toggleTheme}
        darkMode={darkMode}
        isHistoryVisible={showHistory}
      />

      <main className="max-w-4xl mx-auto px-4 pt-6 space-y-8">
        {showHistory ? (
          <SavedBills 
            history={history} 
            onClose={() => setShowHistory(false)} 
            onTogglePaid={togglePaidInHistory}
            onRemoveBill={removeBillFromHistory}
            onViewBill={(entry) => setViewingHistoryEntry(entry)}
            onClearHistory={() => {
              if (window.confirm("Remove all saved bills from history?")) {
                setHistory([]);
                localStorage.removeItem('splitwise_history');
              }
            }}
          />
        ) : (
          <>
            <section className="relative">
              <PeopleManager 
                people={people} 
                onAdd={addPerson} 
                onRemove={removePerson} 
              />
              <button 
                onClick={() => setShowRoulette(true)}
                className="absolute top-4 right-4 bg-amber-100 dark:bg-amber-900/30 text-amber-700 dark:text-amber-400 px-3 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest flex items-center gap-2 hover:bg-amber-200 dark:hover:bg-amber-900/50 transition-colors"
              >
                <i className="fa-solid fa-dice"></i>
                Bill Roulette
              </button>
            </section>

            <section>
              <BillManager 
                items={items} 
                people={people}
                billTitle={billTitle}
                setBillTitle={setBillTitle}
                onAddItem={addItem} 
                onUpdateItem={updateItem}
                onRemoveItem={removeItem}
                onBulkAdd={() => {}} // Legacy
                onClearAll={() => setItems([])}
              />
            </section>

            <section>
              <Summary 
                results={splitResults} 
                totalItems={items.length}
                onTogglePaid={togglePersonPaid}
                onSave={() => {
                  saveToHistory(splitResults);
                  alert("Bill saved to history!");
                }}
                onClear={clearCurrent}
              />
            </section>
          </>
        )}
      </main>

      {/* Modal for viewing active split details */}
      {showSplitModal && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
          <div className="bg-white dark:bg-slate-900 w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">
            <div className="flex justify-between items-center p-6 border-b border-slate-100 dark:border-slate-800 bg-white dark:bg-slate-900 sticky top-0 z-10">
              <h2 className="text-xl font-bold text-slate-800 dark:text-slate-100">Split Details</h2>
              <button 
                onClick={() => setShowSplitModal(false)}
                className="w-10 h-10 flex items-center justify-center bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 dark:hover:bg-slate-700 text-slate-500 dark:text-slate-400 rounded-full transition-colors"
              >
                <i className="fa-solid fa-xmark"></i>
              </button>
            </div>
            <div className="overflow-y-auto flex-1 custom-scrollbar">
              <Summary 
                results={splitResults} 
                totalItems={items.length}
                onTogglePaid={togglePersonPaid}
                onSave={() => saveToHistory(splitResults)}
                onClear={clearCurrent}
                isModal
              />
            </div>
          </div>
        </div>
      )}

      {/* Modal for viewing saved bill details from history */}
      {viewingHistoryEntry && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
          <div className="bg-white dark:bg-slate-900 w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">
            <div className="flex justify-between items-center p-6 border-b border-slate-100 dark:border-slate-800 bg-white dark:bg-slate-900 sticky top-0 z-10">
              <div>
                <h2 className="text-xl font-bold text-slate-800 dark:text-slate-100 line-clamp-1">{viewingHistoryEntry.title}</h2>
                <p className="text-[10px] text-slate-400 dark:text-slate-500 font-bold uppercase tracking-widest">{viewingHistoryEntry.date}</p>
              </div>
              <button 
                onClick={() => setViewingHistoryEntry(null)}
                className="w-10 h-10 flex items-center justify-center bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 dark:hover:bg-slate-700 text-slate-500 dark:text-slate-400 rounded-full transition-colors"
              >
                <i className="fa-solid fa-xmark"></i>
              </button>
            </div>
            <div className="overflow-y-auto flex-1 custom-scrollbar">
              <Summary 
                results={viewingHistoryEntry.results} 
                totalItems={viewingHistoryEntry.results.reduce((acc, r) => acc + r.items.length, 0)}
                onTogglePaid={(personId) => togglePaidInHistory(viewingHistoryEntry.id, personId)}
                onSave={() => {}} 
                onClear={() => {}} 
                isModal
                isHistoryView
              />
            </div>
          </div>
        </div>
      )}

      {!showHistory && !showSplitModal && !viewingHistoryEntry && (
        <div className="fixed bottom-0 left-0 right-0 bg-white dark:bg-slate-900 border-t border-slate-200 dark:border-slate-800 p-4 md:hidden flex justify-between items-center shadow-lg z-50 transition-colors">
          <div className="text-sm font-medium text-slate-500 dark:text-slate-400">
            Total: <span className="text-indigo-600 dark:text-indigo-400 font-bold">₱{splitResults.reduce((acc, r) => acc + r.total, 0).toLocaleString(undefined, { minimumFractionDigits: 2 })}</span>
          </div>
          <button 
            onClick={() => setShowSplitModal(true)}
            className="bg-indigo-600 dark:bg-indigo-500 text-white px-6 py-2.5 rounded-full text-sm font-bold shadow-lg shadow-indigo-100 dark:shadow-none active:scale-95 transition-transform flex items-center gap-2"
          >
            <i className="fa-solid fa-expand text-xs"></i>
            View Split
          </button>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';

interface Props {
  onFinish: () => void;
}

const Onboarding: React.FC<Props> = ({ onFinish }) => {
  const [step, setStep] = useState(0);

  const steps = [
    {
      title: "Welcome to Bayad Buddy",
      description: "Splitting bills shouldn't be a headache. Whether it's a group dinner or a quick coffee, we've got you covered.",
      icon: "fa-hand-peace",
      color: "text-indigo-500",
      bg: "bg-indigo-50 dark:bg-indigo-900/20"
    },
    {
      title: "Add your Crew",
      description: "Start by adding the people you're splitting with. Give everyone a name and watch them get their own unique avatar color.",
      icon: "fa-users-plus",
      color: "text-emerald-500",
      bg: "bg-emerald-50 dark:bg-emerald-900/20"
    },
    {
      title: "Itemize & Assign",
      description: "Add items and tap on people's names to assign who owes what. We calculate the math so you don't have to.",
      icon: "fa-receipt",
      color: "text-amber-500",
      bg: "bg-amber-50 dark:bg-amber-900/20"
    },
    {
      title: "Split & Share",
      description: "Instantly see how much everyone owes. Save your splits for later or share a beautiful breakdown image with the group.",
      icon: "fa-share-nodes",
      color: "text-rose-500",
      bg: "bg-rose-50 dark:bg-rose-900/20"
    }
  ];

  const next = () => {
    if (step < steps.length - 1) {
      setStep(step + 1);
    } else {
      onFinish();
    }
  };

  const currentStep = steps[step];

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-950/80 backdrop-blur-xl">
      <div className="bg-white dark:bg-slate-900 w-full max-w-lg rounded-[2.5rem] shadow-2xl p-8 flex flex-col items-center relative overflow-hidden transition-all duration-500">

        {/* Progress dots */}
        <div className="flex gap-2 mb-8">
          {steps.map((_, i) => (
            <div 
              key={i} 
              className={`h-1.5 rounded-full transition-all duration-300 ${i === step ? 'w-8 bg-indigo-600' : 'w-2 bg-slate-200 dark:bg-slate-800'}`}
            />
          ))}
        </div>

        {/* Content */}
        <div className="flex-1 flex flex-col items-center text-center">
          <div className={`w-24 h-24 rounded-3xl ${currentStep.bg} flex items-center justify-center mb-8 transition-all duration-500`}>
            <i className={`fa-solid ${currentStep.icon} ${currentStep.color} text-4xl`}></i>
          </div>

          <h2 className="text-3xl font-black text-slate-900 dark:text-slate-50 tracking-tight mb-4 transition-all">
            {currentStep.title}
          </h2>
          <p className="text-slate-500 dark:text-slate-400 font-medium leading-relaxed px-4">
            {currentStep.description}
          </p>
        </div>

        {/* Buttons */}
        <div className="w-full mt-10 space-y-3">
          <button
            onClick={next}
            className="w-full py-4 bg-indigo-600 hover:bg-indigo-700 text-white rounded-2xl font-black shadow-xl shadow-indigo-200 dark:shadow-none transition-all active:scale-95"
          >
            {step === steps.length - 1 ? "GET STARTED" : "CONTINUE"}
          </button>

          <button
            onClick={onFinish}
            className="w-full py-2 text-slate-400 dark:text-slate-500 font-bold text-sm hover:text-slate-600 dark:hover:text-slate-300 transition-colors"
          >
            Skip Intro
          </button>
        </div>

        {/* Background Decorations */}
