import React, { useState, useEffect, useMemo } from 'react';
import { Person } from '../types';

interface Props {
  people: Person[];
  onClose: () => void;
}

const Roulette: React.FC<Props> = ({ people, onClose }) => {
  const [isSpinning, setIsSpinning] = useState(false);
  const [rotation, setRotation] = useState(0);
  const [winner, setWinner] = useState<Person | null>(null);
  const [showResult, setShowResult] = useState(false);

  // Map tailwind classes to hex for the canvas/conic gradient
  const colorMap: Record<string, string> = {
    'bg-blue-500': '#3b82f6',
    'bg-purple-500': '#a855f7',
    'bg-pink-500': '#ec4899',
    'bg-emerald-500': '#10b981',
    'bg-orange-500': '#f97316',
    'bg-indigo-500': '#6366f1',
    'bg-rose-500': '#f43f5e',
    'bg-cyan-500': '#06b6d4'
  };

  const spin = () => {
    if (isSpinning) return;

    setIsSpinning(true);
    setShowResult(false);
    setWinner(null);

    const extraSpins = 5 + Math.random() * 5;
    const newRotation = rotation + (extraSpins * 360) + Math.random() * 360;
    setRotation(newRotation);

    setTimeout(() => {
      setIsSpinning(false);
      // Calculate winner based on final rotation
      const normalizedRotation = (newRotation % 360);
      const degreesPerPerson = 360 / people.length;
      // The pointer is at the top (0 deg). 
      // The wheel rotates clockwise, so we subtract from 360.
      const winningIndex = Math.floor(((360 - (normalizedRotation % 360)) % 360) / degreesPerPerson);
      setWinner(people[winningIndex]);
      setShowResult(true);
    }, 4000);
  };

  // Generate the conic gradient for the wheel
  const wheelStyle = useMemo(() => {
    const segmentDegree = 360 / people.length;
    const gradientParts = people.map((p, i) => {
      const color = colorMap[p.avatarColor] || '#cbd5e1';
      return `${color} ${i * segmentDegree}deg ${(i + 1) * segmentDegree}deg`;
    });

    return {
      background: `conic-gradient(${gradientParts.join(', ')})`,
      transform: `rotate(${rotation}deg)`,
      transition: isSpinning ? 'transform 4s cubic-bezier(0.15, 0, 0.15, 1)' : 'none'
    };
  }, [people, rotation, isSpinning]);

  return (
    <div className="fixed inset-0 z-[70] flex items-center justify-center p-4 bg-slate-950/80 backdrop-blur-md">
      <div className="bg-white dark:bg-slate-900 w-full max-w-md rounded-[2.5rem] shadow-2xl p-8 flex flex-col items-center relative overflow-hidden">
        {/* Close Button */}
        <button 
          onClick={onClose}
          className="absolute top-6 right-6 w-10 h-10 flex items-center justify-center bg-slate-100 dark:bg-slate-800 rounded-full text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 transition-colors z-10"
        >
          <i className="fa-solid fa-xmark"></i>
        </button>

        <div className="text-center mb-8">
          <h2 className="text-2xl font-black text-slate-900 dark:text-slate-50 tracking-tight">Bill Roulette</h2>
          <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mt-1">One person pays it all!</p>
        </div>

        {/* The Wheel UI */}
        <div className="relative w-64 h-64 mb-10 group">
          {/* Pointer */}
          <div className="absolute top-0 left-1/2 -translate-x-1/2 -translate-y-1/2 z-20 w-8 h-10 drop-shadow-lg pointer-events-none">
            <div className="w-full h-full bg-slate-900 dark:bg-white clip-triangle flex items-end justify-center pb-1">
               <div className="w-1 h-1 bg-rose-500 rounded-full animate-pulse"></div>
            </div>
          </div>

          {/* Center Pin */}
          <div className="absolute inset-0 m-auto w-12 h-12 bg-white dark:bg-slate-900 rounded-full shadow-xl z-20 border-4 border-slate-100 dark:border-slate-800 flex items-center justify-center">
            <i className="fa-solid fa-mug-hot text-indigo-500 text-sm"></i>
          </div>

          {/* Actual Rotating Wheel */}
          <div 
            className="w-full h-full rounded-full border-8 border-slate-100 dark:border-slate-800 shadow-inner overflow-hidden relative"
            style={wheelStyle}
          >
            {/* Person Names on Wheel */}
            {people.map((p, i) => {
              const segmentDegree = 360 / people.length;
              const rotationVal = i * segmentDegree + segmentDegree / 2;
              return (
                <div 
                  key={p.id}
                  className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-full h-full flex items-start justify-center pointer-events-none"
                  style={{ transform: `rotate(${rotationVal}deg)` }}
                >
                   <span 
                    className="inline-block mt-8 px-2 font-black text-white drop-shadow-md truncate uppercase tracking-tighter"
                    style={{ 
                      fontSize: people.length > 8 ? '8px' : '10px',
                      maxWidth: `${200 / (people.length / 2)}px`
                    }}
                   >
                    {p.name}
                   </span>
                </div>
              );
            })}
          </div>

          {/* Decorative Outer Ring */}
          <div className="absolute -inset-4 border-4 border-dashed border-slate-200 dark:border-slate-800 rounded-full animate-[spin_20s_linear_infinite] opacity-30"></div>
        </div>

        {/* Interaction Area */}
        <div className="w-full text-center space-y-6">
          {!showResult ? (
            <button
              onClick={spin}
              disabled={isSpinning}
              className={`w-full py-4 rounded-2xl font-black text-white shadow-xl transition-all active:scale-95 ${
                isSpinning ? 'bg-slate-300 dark:bg-slate-700 cursor-not-allowed' : 'bg-indigo-600 hover:bg-indigo-700'
              }`}
            >
              {isSpinning ? 'LUCK IS DECIDING...' : 'SPIN THE WHEEL'}
            </button>
          ) : (
            <div className="animate-[bounce_0.5s_ease-out]">
              <div className="inline-flex items-center gap-4 bg-emerald-50 dark:bg-emerald-950/30 border border-emerald-100 dark:border-emerald-900/50 p-6 rounded-3xl w-full mb-6">
                <div className={`w-16 h-16 rounded-full ${winner?.avatarColor} flex items-center justify-center text-2xl text-white font-black shadow-lg animate-pulse`}>
                  {winner?.name.charAt(0).toUpperCase()}
                </div>
                <div className="text-left">
                  <p className="text-[10px] font-black uppercase tracking-[0.2em] text-emerald-600 dark:text-emerald-400">The Winner</p>
                  <h3 className="text-2xl font-black text-slate-900 dark:text-slate-50">{winner?.name}</h3>
                  <p className="text-xs text-slate-500 font-medium italic">Better luck next time!</p>
                </div>
              </div>

              <div className="flex gap-3">
                <button
                  onClick={spin}
                  className="flex-1 py-3 bg-slate-100 dark:bg-slate-800 text-slate-700 dark:text-slate-200 rounded-xl font-bold text-sm hover:bg-slate-200 dark:hover:bg-slate-700 transition-colors"
                >
                  Spin Again
                </button>
                <button
                  onClick={onClose}
                  className="flex-1 py-3 bg-indigo-600 text-white rounded-xl font-bold text-sm hover:bg-indigo-700 transition-colors shadow-lg shadow-indigo-100 dark:shadow-none"
                >
                  Got it
                </button>
              </div>
            </div>
          )}
        </div>

        {/* Background Confetti Logic (Visual Only) */}
        {showResult && (
          <div className="absolute inset-0 pointer-events-none overflow-hidden">
             {[...Array(20)].map((_, i) => (
               <div 
                key={i}
                className="absolute w-2 h-2 rounded-full animate-confetti"
                style={{
                  left: `${Math.random() * 100}%`,
                  backgroundColor: Object.values(colorMap)[Math.floor(Math.random() * 8)],
                  animationDelay: `${Math.random() * 2}s`
                }}
               />
             ))}
          </div>
        )}
      </div>

      <style dangerouslySetInnerHTML={{ __html: `
        .clip-triangle {
          clip-path: polygon(50% 100%, 0 0, 100% 0);
        }
        @keyframes confetti {
          0% { transform: translateY(-20px) rotate(0deg); opacity: 1; }
          100% { transform: translateY(500px) rotate(720deg); opacity: 0; }
        }
        .animate-confetti {
          animation: confetti 2s ease-out forwards;
        }
      `}} />
    </div>
  );
};

export default Roulette;

export interface Person {
  id: string;
  name: string;
  avatarColor: string;
}

export interface UserProfile {
  name: string;
  paymentMethod: 'GCash' | 'Maya' | 'Bank' | 'Other' | '';
  paymentDetails: string;
  bankName?: string;
  accountNumber?: string;
}

export interface BillItem {
  id: string;
  name: string;
  price: number;
  assignedPersonIds: string[];
}

export interface SplitResult {
  person: Person;
  items: { itemName: string; share: number }[];
  subtotal: number;
  total: number;
  isPaid: boolean;
}

export interface HistoryEntry {
  id: string;
  date: string;
  title: string;
  total: number;
  results: SplitResult[];
}

export interface RoomParticipant {
  id: string;
  name: string;
  isHost: boolean;
}

export interface RoomSession {
  roomId: string | null;
  isHost: boolean;
  status: 'idle' | 'connecting' | 'connected';
  participants: RoomParticipant[];
}

import React, { useState, useEffect } from 'react';
import { RoomSession, UserProfile } from '../types';

interface Props {
  session: RoomSession;
  userProfile: UserProfile;
  onJoin: (code: string) => void;
  onCreate: () => void;
  onLeave: () => void;
  onClose: () => void;
}

