  const [loser, setLoser] = useState<Person | null>(null);
  const [rotation, setRotation] = useState(0);

  // Participants positions for chairs (N-1) and for the walking circle
  const chairCount = people.length - 1;

  useEffect(() => {
    let interval: any;
    if (gameState === 'playing') {
      interval = setInterval(() => {
        setRotation(prev => prev + 5);
      }, 50);
    } else {
      clearInterval(interval);
    }
    return () => clearInterval(interval);
  }, [gameState]);

  const startGame = () => {
    if (gameState !== 'idle' && gameState !== 'result') return;

    setGameState('playing');
    setLoser(null);

    // Random music duration between 3-6 seconds
    const duration = 3000 + Math.random() * 3000;

    setTimeout(() => {
      setGameState('scrambling');

      // Select the payer (the one who "didn't sit")
      const losingIndex = Math.floor(Math.random() * people.length);
      const chosenLoser = people[losingIndex];

      setTimeout(() => {
        setLoser(chosenLoser);
        setGameState('result');
      }, 800); // Time to "scramble" to seats
    }, duration);
  };

  return (
    <div className="fixed inset-0 z-[70] flex items-center justify-center p-4 bg-slate-950/80 backdrop-blur-md">
      <div className="bg-white dark:bg-slate-900 w-full max-w-md rounded-[2.5rem] shadow-2xl p-8 flex flex-col items-center relative overflow-hidden min-h-[500px]">
