        </button>

        <div className="text-center mb-8">
          <h2 className="text-2xl font-black text-slate-900 dark:text-slate-50 tracking-tight">Musical Chairs</h2>
          <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mt-1">Don't be the last one standing!</p>
        </div>

        {/* The Game Arena */}
        <div className="relative w-72 h-72 mb-10">

          {/* Chairs in the center (N-1) */}
          <div className="absolute inset-0 m-auto w-40 h-40 flex items-center justify-center">
             {people.length > 1 && Array.from({ length: chairCount }).map((_, i) => {
