              const angle = (i * 360) / people.length + (gameState === 'playing' ? rotation : 0);

              // During playing/idle, they are in a wide circle
              // During scrambling/result, they snap to center or seats
              let radius = 100;
              let scale = 1;
              let opacity = 1;

              if (gameState === 'scrambling' || gameState === 'result') {
