              if (gameState === 'playing') {
                 // Walking animation bob
                 radius += Math.sin(rotation * 0.1) * 3;
              }

              const x = Math.cos((angle * Math.PI) / 180) * radius;
              const y = Math.sin((angle * Math.PI) / 180) * radius;

              return (
                <div 
                  key={p.id}
                  className="absolute inset-0 m-auto w-12 h-12 flex items-center justify-center transition-all duration-700 ease-out"
                  style={{ 
                    transform: `translate(${x}px, ${y}px) scale(${scale})`,
                    zIndex: isLoser ? 50 : 10
                  }}
                >
                  <div className={`w-10 h-10 rounded-full ${p.avatarColor} border-2 border-white dark:border-slate-900 shadow-xl flex items-center justify-center text-white text-xs font-black relative overflow-hidden`}>
                    {p.name.charAt(0).toUpperCase()}
                    {gameState === 'result' && isLoser && (
                      <div className="absolute inset-0 bg-rose-500/40 flex items-center justify-center">
