                  {gameState !== 'playing' && (
                    <div className="absolute -bottom-6 left-1/2 -translate-x-1/2 bg-white/90 dark:bg-slate-800/90 px-2 py-0.5 rounded text-[8px] font-black uppercase whitespace-nowrap shadow-sm border border-slate-100 dark:border-slate-700">
                      {p.name}
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        </div>

        {/* Game Status & Controls */}
        <div className="w-full text-center mt-auto">
          {gameState === 'idle' && (
            <button
