            <div className="py-4 bg-rose-50 dark:bg-rose-900/20 rounded-2xl border border-rose-100 dark:border-rose-900/30">
              <p className="text-sm font-black text-rose-600 dark:text-rose-400 uppercase tracking-[0.2em] animate-bounce">
                STOP! SCRAMBLE!
              </p>
            </div>
          )}

          {gameState === 'result' && (
            <div className="animate-in fade-in zoom-in duration-500">
