                  opacity: (gameState === 'playing' || gameState === 'loading') ? 0.2 : 1
                }}
              >
                <div className="w-12 h-12 bg-slate-100 dark:bg-slate-800 rounded-2xl flex items-center justify-center shadow-inner">
                  <i className="fa-solid fa-chair text-slate-300 dark:text-slate-600 text-2xl"></i>
                </div>
              </div>
            );
          })}

          {/* People Moving Around - Fixed Alignment */}
          {people.map((p, i) => {
            const isLoser = loserId === p.id;

            let x = 0;
            let y = 0;
            let scale = 1;

            if (gameState === 'idle' || gameState === 'loading') {
              const angle = (i * 360) / people.length - 90;
              x = Math.cos((angle * Math.PI) / 180) * OUTER_RADIUS;
              y = Math.sin((angle * Math.PI) / 180) * OUTER_RADIUS;
            } else if (gameState === 'playing') {
              const angle = (i * 360) / people.length + rotation - 90;
              const bounce = Math.sin(rotation * 0.15) * 5;
              x = Math.cos((angle * Math.PI) / 180) * (OUTER_RADIUS + bounce);
              y = Math.sin((angle * Math.PI) / 180) * (OUTER_RADIUS + bounce);
            } else if (gameState === 'scrambling') {
              const angle = (i * 360) / people.length + rotation - 90;
              x = Math.cos((angle * Math.PI) / 180) * CHAIR_RADIUS;
              y = Math.sin((angle * Math.PI) / 180) * CHAIR_RADIUS;
              scale = 0.85;
            } else if (gameState === 'result' && loserId) {
              if (isLoser) {
                x = 0; y = 0; scale = 1.5;
              } else {
                const chairIndex = winnerPositions[p.id] ?? 0;
                const angle = (chairIndex * 360) / CHAIR_COUNT - 90;
                x = Math.cos((angle * Math.PI) / 180) * CHAIR_RADIUS;
                y = Math.sin((angle * Math.PI) / 180) * CHAIR_RADIUS;
                scale = 1.1; // Slightly larger when "seated"
              }
            }

            return (
              <div 
                key={p.id}
                className="absolute flex items-center justify-center transition-all duration-700 ease-[cubic-bezier(0.175,0.885,0.32,1.275)]"
                style={{ 
                  left: '50%',
                  top: '50%',
                  transform: `translate(calc(-50% + ${x}px), calc(-50% + ${y}px)) scale(${scale})`,
                  zIndex: isLoser ? 50 : 20
                }}
              >
                <div className="relative group">
                  <div className={`w-14 h-14 rounded-[1.25rem] ${p.avatarColor} border-4 border-white dark:border-slate-900 shadow-2xl flex items-center justify-center text-white text-base font-black transition-all ${beatPulse && gameState === 'playing' ? 'scale-110' : 'scale-100'}`}>
                    {p.name.charAt(0).toUpperCase()}
                    {gameState === 'result' && isLoser && (
                      <div className="absolute -top-3 -right-3 w-8 h-8 bg-rose-500 rounded-full flex items-center justify-center text-xs border-4 border-white dark:border-slate-900 animate-bounce shadow-lg">
                        <i className="fa-solid fa-bolt"></i>
                      </div>
                    )}
                  </div>
                  {/* Participant Name */}
                  {gameState !== 'playing' && gameState !== 'loading' && (
                    <div className="absolute -bottom-8 left-1/2 -translate-x-1/2 bg-white dark:bg-slate-800 px-3 py-1 rounded-full shadow-lg border border-slate-100 dark:border-slate-700 text-[10px] font-black uppercase whitespace-nowrap text-slate-700 dark:text-slate-200">
                      {p.name}
                    </div>
                  )}
                </div>
              </div>
            );
          })}
        </div>

        {/* Game Controls */}
        <div className="w-full mt-auto">
          {gameState === 'idle' && (
            <button
              onClick={generateAndPlayMusic}
              className="w-full py-5 bg-indigo-600 hover:bg-indigo-700 text-white rounded-[2rem] font-black shadow-2xl shadow-indigo-200 dark:shadow-none transition-all active:scale-95 flex items-center justify-center gap-4 group"
            >
              <i className="fa-solid fa-play text-xl group-hover:scale-125 transition-transform"></i>
              PLAY WITH BEAT & SONG
            </button>
          )}

          {gameState === 'loading' && (
            <div className="py-5 bg-slate-50 dark:bg-slate-800/50 rounded-[2rem] border-2 border-dashed border-indigo-200 dark:border-indigo-900/40 text-center">
              <p className="text-sm font-black text-indigo-600 dark:text-indigo-400 uppercase tracking-widest flex items-center justify-center gap-3">
                <i className="fa-solid fa-compact-disc fa-spin"></i>
                Mixing Game Audio...
              </p>
            </div>
          )}

          {gameState === 'playing' && (
            <div className={`py-5 bg-white dark:bg-slate-900 rounded-[2rem] border-4 transition-all text-center ${beatPulse ? 'border-indigo-500 shadow-xl' : 'border-slate-100 dark:border-slate-800'}`}>
              <p className="text-sm font-black text-indigo-600 dark:text-indigo-400 uppercase tracking-widest flex items-center justify-center gap-3">
                <i className="fa-solid fa-volume-high animate-pulse"></i>
                Music & Beat Active
              </p>
            </div>
          )}

          {gameState === 'scrambling' && (
            <div className="py-5 bg-rose-600 text-white rounded-[2rem] text-center shadow-2xl shadow-rose-200 dark:shadow-none animate-pulse">
              <p className="text-lg font-black uppercase tracking-[0.25em]">
                SIT DOWN!
              </p>
            </div>
          )}

          {gameState === 'result' && loserId && (
            <div className="animate-in fade-in zoom-in slide-in-from-bottom-4 duration-500">
              <div className="bg-rose-50 dark:bg-rose-950/30 border-2 border-rose-100 dark:border-rose-900/50 p-6 rounded-[2.5rem] w-full mb-6 flex items-center gap-5 shadow-inner">
                <div className="w-16 h-16 rounded-2xl bg-rose-500 flex items-center justify-center text-3xl text-white shadow-xl shadow-rose-500/30">
                  <i className="fa-solid fa-money-bill-wave"></i>
                </div>
                <div className="text-left">
                  <p className="text-[10px] font-black uppercase tracking-[0.2em] text-rose-600 dark:text-rose-400">The Loser Pays</p>
                  <h3 className="text-2xl font-black text-slate-900 dark:text-slate-50">{people.find(p => p.id === loserId)?.name}</h3>
                  <p className="text-xs text-slate-500 font-medium italic">Better luck next time! 💸</p>
                </div>
              </div>

              <div className="flex gap-4">
                <button
                  onClick={generateAndPlayMusic}
                  className="flex-1 py-4 bg-slate-100 dark:bg-slate-800 text-slate-700 dark:text-slate-200 rounded-2xl font-black text-sm hover:bg-slate-200 dark:hover:bg-slate-700 transition-colors"
                >
                  REMATCH
                </button>
                <button
                  onClick={onClose}
                  className="flex-1 py-4 bg-indigo-600 text-white rounded-2xl font-black text-sm hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-200 dark:shadow-none active:scale-95"
                >
                  GOT IT
                </button>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

