import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Person } from '../types';

interface Props {
  people: Person[];
  onClose: () => void;
}

const MusicalChairs: React.FC<Props> = ({ people, onClose }) => {
  const [gameState, setGameState] = useState<'idle' | 'playing' | 'scrambling' | 'result'>('idle');
  const [loserId, setLoserId] = useState<string | null>(null);
  const [rotation, setRotation] = useState(0);

  const audioContextRef = useRef<AudioContext | null>(null);
  const beatIntervalRef = useRef<number | null>(null);

  // Constants for layout
  const ARENA_SIZE = 280;
  const CHAIR_RADIUS = 50;
  const OUTER_RADIUS = 110;
  const CHAIR_COUNT = people.length - 1;

  // Cleanup audio on unmount
  useEffect(() => {
    return () => {
      stopAudio();
      if (audioContextRef.current) {
        audioContextRef.current.close();
      }
    };
  }, []);

  const stopAudio = () => {
    if (beatIntervalRef.current) {
      window.clearInterval(beatIntervalRef.current);
      beatIntervalRef.current = null;
    }
  };

  const playMerryBeat = () => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    }

    const ctx = audioContextRef.current;
    if (ctx.state === 'suspended') {
      ctx.resume();
    }

    let step = 0;
    const tempo = 135; // BPM
    const stepDuration = 60 / tempo / 2; // 8th notes

    const notes = [261.63, 329.63, 392.00, 440.00]; // C4, E4, G4, A4 (C Major Pentatonic)

    beatIntervalRef.current = window.setInterval(() => {
      const now = ctx.currentTime;

      // 1. Kick Drum (Steps 0, 4, 8, 12)
      if (step % 4 === 0) {
        const osc = ctx.createOscillator();
        const gain = ctx.createGain();
        osc.frequency.setValueAtTime(150, now);
        osc.frequency.exponentialRampToValueAtTime(40, now + 0.1);
        gain.gain.setValueAtTime(0.5, now);
        gain.gain.exponentialRampToValueAtTime(0.01, now + 0.1);
        osc.connect(gain).connect(ctx.destination);
        osc.start(now);
        osc.stop(now + 0.1);
      }

      // 2. Snare / Clap (Steps 2, 6, 10, 14)
      if (step % 4 === 2) {
        const bufferSize = ctx.sampleRate * 0.1;
        const buffer = ctx.createBuffer(1, bufferSize, ctx.sampleRate);
        const data = buffer.getChannelData(0);
        for (let i = 0; i < bufferSize; i++) {
          data[i] = Math.random() * 2 - 1;
        }
        const noise = ctx.createBufferSource();
        noise.buffer = buffer;
        const filter = ctx.createBiquadFilter();
        filter.type = 'highpass';
        filter.frequency.value = 1000;
        const gain = ctx.createGain();
        gain.gain.setValueAtTime(0.2, now);
        gain.gain.exponentialRampToValueAtTime(0.01, now + 0.1);
        noise.connect(filter).connect(gain).connect(ctx.destination);
        noise.start(now);
      }

      // 3. Merry Melody
      if (step % 2 === 0) {
        const osc = ctx.createOscillator();
        const gain = ctx.createGain();
        const noteIdx = Math.floor(Math.random() * notes.length);
        osc.type = 'triangle';
        osc.frequency.setValueAtTime(notes[noteIdx], now);
        gain.gain.setValueAtTime(0.05, now);
        gain.gain.exponentialRampToValueAtTime(0.001, now + 0.2);
        osc.connect(gain).connect(ctx.destination);
        osc.start(now);
        osc.stop(now + 0.2);
      }

      step = (step + 1) % 16;
    }, stepDuration * 1000);
  };

  useEffect(() => {
    let interval: any;
    if (gameState === 'playing') {
      interval = setInterval(() => {
        setRotation(prev => prev + 4);
      }, 30);
    } else {
      clearInterval(interval);
      if (gameState !== 'playing') {
        stopAudio();
      }
    }
    return () => clearInterval(interval);
  }, [gameState]);

  const startGame = () => {
    if (gameState === 'playing' || gameState === 'scrambling') return;

    setGameState('playing');
    setLoserId(null);
    playMerryBeat();

    // Random music duration between 4-7 seconds for more suspense
    const duration = 4000 + Math.random() * 3000;

    setTimeout(() => {
      setGameState('scrambling');
      stopAudio();

      // Determine the loser
      const losingIndex = Math.floor(Math.random() * people.length);
      const chosenLoser = people[losingIndex];

      // Artificial delay for the "scramble" effect
      setTimeout(() => {
        setLoserId(chosenLoser.id);
        setGameState('result');
      }, 1000);
    }, duration);
  };

  // Pre-calculate winner indices to map them to chairs
  const winnerPositions = useMemo(() => {
    if (!loserId) return {};
    const winners = people.filter(p => p.id !== loserId);
    const mapping: Record<string, number> = {};
    winners.forEach((p, i) => {
      mapping[p.id] = i;
    });
    return mapping;
  }, [loserId, people]);

  return (
    <div className="fixed inset-0 z-[70] flex items-center justify-center p-4 bg-slate-950/80 backdrop-blur-md">
      <div className="bg-white dark:bg-slate-900 w-full max-w-md rounded-[2.5rem] shadow-2xl p-8 flex flex-col items-center relative overflow-hidden min-h-[580px]">
        {/* Close Button */}
        <button 
          onClick={onClose}
          className="absolute top-6 right-6 w-10 h-10 flex items-center justify-center bg-slate-100 dark:bg-slate-800 rounded-full text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 transition-colors z-20"
        >
          <i className="fa-solid fa-xmark"></i>
        </button>

        <div className="text-center mb-6">
          <h2 className="text-2xl font-black text-slate-900 dark:text-slate-50 tracking-tight">Musical Chairs</h2>
          <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mt-1">Don't be the last one standing!</p>
        </div>

        {/* The Game Arena */}
        <div 
          className="relative flex items-center justify-center mb-10"
          style={{ width: ARENA_SIZE, height: ARENA_SIZE }}
        >
          {/* Central Decoration / Payer Zone */}
          <div className="absolute w-24 h-24 bg-slate-50 dark:bg-slate-800/50 rounded-full border-2 border-dashed border-slate-200 dark:border-slate-700 flex items-center justify-center">
             {gameState === 'playing' && (
               <div className="flex flex-col items-center animate-bounce">
                 <i className="fa-solid fa-music text-indigo-500 text-2xl mb-1"></i>
                 <div className="flex gap-1">
                   <span className="w-1 h-3 bg-indigo-400 rounded-full animate-[pulse_1s_infinite]"></span>
                   <span className="w-1 h-5 bg-indigo-500 rounded-full animate-[pulse_0.8s_infinite]"></span>
                   <span className="w-1 h-3 bg-indigo-400 rounded-full animate-[pulse_1.2s_infinite]"></span>
                 </div>
               </div>
             )}
          </div>

          {/* Chairs in a circle */}
          {people.length > 1 && Array.from({ length: CHAIR_COUNT }).map((_, i) => {
            const angle = (i * 360) / CHAIR_COUNT;
            const x = Math.cos((angle * Math.PI) / 180) * CHAIR_RADIUS;
            const y = Math.sin((angle * Math.PI) / 180) * CHAIR_RADIUS;

            return (
              <div 
                key={`chair-${i}`}
                className="absolute transition-all duration-700 flex items-center justify-center"
                style={{ 
                  transform: `translate(${x}px, ${y}px) rotate(${angle + 90}deg)`,
                  opacity: gameState === 'playing' ? 0.3 : 1
                }}
              >
                <div className="w-10 h-10 bg-slate-100 dark:bg-slate-800 rounded-xl flex items-center justify-center shadow-inner">
                  <i className="fa-solid fa-chair text-slate-300 dark:text-slate-600 text-xl"></i>
                </div>
              </div>
            );
          })}

          {/* People Moving Around */}
          {people.map((p, i) => {
            const isLoser = loserId === p.id;

            let x = 0;
            let y = 0;
            let scale = 1;

            if (gameState === 'idle') {
              // Initial circle placement
              const angle = (i * 360) / people.length;
              x = Math.cos((angle * Math.PI) / 180) * OUTER_RADIUS;
              y = Math.sin((angle * Math.PI) / 180) * OUTER_RADIUS;
            } else if (gameState === 'playing') {
              // Orbiting animation
              const angle = (i * 360) / people.length + rotation;
              const bounce = Math.sin(rotation * 0.2) * 4;
              x = Math.cos((angle * Math.PI) / 180) * (OUTER_RADIUS + bounce);
              y = Math.sin((angle * Math.PI) / 180) * (OUTER_RADIUS + bounce);
            } else if (gameState === 'scrambling') {
              // Everyone rushes towards center/chairs randomly
              const angle = (i * 360) / people.length + rotation;
              x = Math.cos((angle * Math.PI) / 180) * CHAIR_RADIUS;
              y = Math.sin((angle * Math.PI) / 180) * CHAIR_RADIUS;
              scale = 0.9;
            } else if (gameState === 'result' && loserId) {
              if (isLoser) {
                // Loser is in the center
                x = 0;
                y = 0;
                scale = 1.4;
              } else {
                // Winners sit on chairs
                const chairIndex = winnerPositions[p.id] ?? 0;
                const angle = (chairIndex * 360) / CHAIR_COUNT;
                x = Math.cos((angle * Math.PI) / 180) * CHAIR_RADIUS;
                y = Math.sin((angle * Math.PI) / 180) * CHAIR_RADIUS;
                scale = 0.95;
              }
            }

            return (
              <div 
                key={p.id}
                className="absolute flex items-center justify-center transition-all duration-700 ease-[cubic-bezier(0.34,1.56,0.64,1)]"
                style={{ 
                  transform: `translate(${x}px, ${y}px) scale(${scale})`,
                  zIndex: isLoser ? 50 : 20
                }}
              >
                <div className="relative group">
                  <div className={`w-12 h-12 rounded-2xl ${p.avatarColor} border-4 border-white dark:border-slate-900 shadow-xl flex items-center justify-center text-white text-sm font-black transition-all`}>
                    {p.name.charAt(0).toUpperCase()}
                    {gameState === 'result' && isLoser && (
                      <div className="absolute -top-2 -right-2 w-6 h-6 bg-rose-500 rounded-full flex items-center justify-center text-[10px] border-2 border-white dark:border-slate-900 animate-bounce">
                        <i className="fa-solid fa-bolt"></i>
                      </div>
                    )}
                  </div>

                  {/* Name Tag (hidden during play) */}
                  {gameState !== 'playing' && (
                    <div className="absolute -bottom-6 left-1/2 -translate-x-1/2 bg-white dark:bg-slate-800 px-2 py-0.5 rounded shadow-sm border border-slate-100 dark:border-slate-700 text-[9px] font-black uppercase whitespace-nowrap text-slate-600 dark:text-slate-300">
                      {p.name}
                    </div>
                  )}
                </div>
              </div>
            );
          })}
        </div>

        {/* Game Status & Controls */}
        <div className="w-full mt-auto">
          {gameState === 'idle' && (
            <button
              onClick={startGame}
              className="w-full py-4 bg-indigo-600 hover:bg-indigo-700 text-white rounded-2xl font-black shadow-xl shadow-indigo-100 dark:shadow-none transition-all active:scale-95 flex items-center justify-center gap-3"
            >
              <i className="fa-solid fa-play"></i>
              START MUSIC
            </button>
          )}

          {gameState === 'playing' && (
            <div className="py-4 bg-slate-50 dark:bg-slate-800/50 rounded-2xl border-2 border-indigo-100 dark:border-indigo-900/30 text-center">
              <p className="text-sm font-black text-indigo-600 dark:text-indigo-400 uppercase tracking-widest flex items-center justify-center gap-2">
                <span className="w-1.5 h-1.5 bg-indigo-500 rounded-full animate-ping"></span>
                Music is Playing...
              </p>
            </div>
          )}

          {gameState === 'scrambling' && (
            <div className="py-4 bg-rose-50 dark:bg-rose-900/20 rounded-2xl border-2 border-rose-100 dark:border-rose-900/30 text-center animate-pulse">
              <p className="text-sm font-black text-rose-600 dark:text-rose-400 uppercase tracking-[0.2em]">
                STOP! FIND A SEAT!
              </p>
            </div>
          )}

          {gameState === 'result' && loserId && (
            <div className="animate-in fade-in zoom-in duration-500">
              <div className="bg-rose-50 dark:bg-rose-950/30 border border-rose-100 dark:border-rose-900/50 p-5 rounded-3xl w-full mb-6 flex items-center gap-4">
                <div className="w-14 h-14 rounded-2xl bg-rose-500 flex items-center justify-center text-2xl text-white shadow-lg shadow-rose-200 dark:shadow-none">
                  <i className="fa-solid fa-receipt"></i>
                </div>
                <div className="text-left">
                  <p className="text-[10px] font-black uppercase tracking-[0.2em] text-rose-600 dark:text-rose-400">The standing payer</p>
                  <h3 className="text-xl font-black text-slate-900 dark:text-slate-50">{people.find(p => p.id === loserId)?.name}</h3>
                  <p className="text-xs text-slate-500 font-medium italic">You're paying the bill! 💸</p>
                </div>
              </div>

              <div className="flex gap-3">
                <button
                  onClick={startGame}
                  className="flex-1 py-3 bg-slate-100 dark:bg-slate-800 text-slate-700 dark:text-slate-200 rounded-xl font-bold text-sm hover:bg-slate-200 dark:hover:bg-slate-700 transition-colors"
                >
                  Rematch
                </button>
                <button
                  onClick={onClose}
                  className="flex-1 py-3 bg-indigo-600 text-white rounded-xl font-bold text-sm hover:bg-indigo-700 transition-colors shadow-lg shadow-indigo-100 dark:shadow-none"
                >
                  Confirm
                </button>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

