                   <span className="w-1.5 h-5 bg-indigo-500 rounded-full animate-[pulse_0.4s_infinite]"></span>
                   <span className="w-1.5 h-4 bg-indigo-400 rounded-full animate-[pulse_0.8s_infinite]"></span>
                 </div>
               </div>
             )}
          </div>

