                  <i className="fa-solid fa-receipt"></i>
                </div>
                <div className="text-left">
                  <p className="text-[10px] font-black uppercase tracking-[0.2em] text-rose-600 dark:text-rose-400">Furthest from seat</p>
                  <h3 className="text-2xl font-black text-slate-900 dark:text-slate-50">{people.find(p => p.id === loserId)?.name}</h3>
