  const [showProfile, setShowProfile] = useState(false);

  // Initialize state from LocalStorage or defaults
  const [people, setPeople] = useState<Person[]>(() => {
    const saved = localStorage.getItem('splitwise_people');
    if (saved) return JSON.parse(saved);

    // Default "Me" person should use the profile name
    const initialName = localStorage.getItem('bayad_buddy_profile') 
      ? JSON.parse(localStorage.getItem('bayad_buddy_profile')!).name 
      : 'Me';

    return [{ id: '1', name: initialName, avatarColor: AVATAR_COLORS[0] }];
  });

  const [items, setItems] = useState<BillItem[]>(() => {
    const saved = localStorage.getItem('splitwise_items');
    return saved ? JSON.parse(saved) : [];
  });

  const [billTitle, setBillTitle] = useState(() => {
    return localStorage.getItem('splitwise_bill_title') || '';
  });

  const [paidStatus, setPaidStatus] = useState<Record<string, boolean>>(() => {
    const saved = localStorage.getItem('splitwise_paid_status');
    return saved ? JSON.parse(saved) : {};
  });

  const [history, setHistory] = useState<HistoryEntry[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [showSplitModal, setShowSplitModal] = useState(false);
  const [showChairs, setShowChairs] = useState(false);
  const [viewingHistoryEntry, setViewingHistoryEntry] = useState<HistoryEntry | null>(null);
  const [showOnboarding, setShowOnboarding] = useState(() => {
    return localStorage.getItem('bayad_buddy_onboarded') !== 'true';
  });

  const [darkMode, setDarkMode] = useState(() => {
    return localStorage.getItem('splitwise_theme') === 'dark';
  });

  // Sync state to LocalStorage
  useEffect(() => {
    localStorage.setItem('bayad_buddy_profile', JSON.stringify(userProfile));
    // Automatically update the first person's name if they were the "Me" user
    setPeople(prev => prev.map((p, i) => i === 0 ? { ...p, name: userProfile.name } : p));
  }, [userProfile]);

  useEffect(() => {
    localStorage.setItem('splitwise_people', JSON.stringify(people));
  }, [people]);

  useEffect(() => {
    localStorage.setItem('splitwise_items', JSON.stringify(items));
  }, [items]);

  useEffect(() => {
    localStorage.setItem('splitwise_bill_title', billTitle);
  }, [billTitle]);

  useEffect(() => {
    localStorage.setItem('splitwise_paid_status', JSON.stringify(paidStatus));
  }, [paidStatus]);

  // Theme effect
  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('splitwise_theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('splitwise_theme', 'light');
    }
  }, [darkMode]);

  // Persistence for history
  useEffect(() => {
    const saved = localStorage.getItem('splitwise_history');
    if (saved) {
      try {
        setHistory(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to load history", e);
      }
    }
  }, []);

  const toggleTheme = () => setDarkMode(!darkMode);

  const togglePersonPaid = (personId: string) => {
    setPaidStatus(prev => ({
      ...prev,
      [personId]: !prev[personId]
    }));
  };

  const togglePaidInHistory = (billId: string, personId: string) => {
    const updatedHistory = history.map(entry => {
      if (entry.id === billId) {
        const updatedEntry = {
          ...entry,
          results: entry.results.map(res => 
            res.person.id === personId ? { ...res, isPaid: !res.isPaid } : res
          )
        };
        if (viewingHistoryEntry?.id === billId) {
          setViewingHistoryEntry(updatedEntry);
        }
        return updatedEntry;
      }
      return entry;
    });
    setHistory(updatedHistory);
    localStorage.setItem('splitwise_history', JSON.stringify(updatedHistory));
  };

  const removeBillFromHistory = (billId: string) => {
    const updatedHistory = history.filter(entry => entry.id !== billId);
    setHistory(updatedHistory);
    localStorage.setItem('splitwise_history', JSON.stringify(updatedHistory));
  };

  const saveToHistory = (results: SplitResult[]) => {
    if (items.length === 0) return;

    const generateId = () => {
      try {
        return crypto.randomUUID();
      } catch (e) {
        return Math.random().toString(36).substring(2, 15) + Date.now().toString(36);
      }
    };

    const total = items.reduce((acc, item) => acc + item.price, 0);
    const newEntry: HistoryEntry = {
      id: generateId(),
      date: new Date().toLocaleString(),
      title: billTitle.trim() || (items.length > 0 ? items[0].name + (items.length > 1 ? '...' : '') : 'Quick Split'),
      total,
      results: JSON.parse(JSON.stringify(results)) 
    };

    const updatedHistory = [newEntry, ...history];
    setHistory(updatedHistory);
    localStorage.setItem('splitwise_history', JSON.stringify(updatedHistory));
  };

  const clearCurrent = () => {
    if (window.confirm("Clear all items and people?")) {
      setItems([]);
      setBillTitle('');
      setPeople([{ id: '1', name: userProfile.name, avatarColor: AVATAR_COLORS[0] }]);
      setPaidStatus({});
      localStorage.removeItem('splitwise_items');
      localStorage.removeItem('splitwise_bill_title');
      localStorage.removeItem('splitwise_people');
      localStorage.removeItem('splitwise_paid_status');
    }
  };

  const addPerson = (name: string) => {
    const newPerson: Person = {
      id: Math.random().toString(36).substring(2, 9),
      name,
      avatarColor: AVATAR_COLORS[people.length % AVATAR_COLORS.length]
    };
    setPeople([...people, newPerson]);
  };

  const removePerson = (id: string) => {
    if (people.length <= 1) return;
    setPeople(people.filter(p => p.id !== id));
    setItems(items.map(item => ({
      ...item,
      assignedPersonIds: item.assignedPersonIds.filter(pid => pid !== id)
    })));
    const newPaidStatus = { ...paidStatus };
    delete newPaidStatus[id];
    setPaidStatus(newPaidStatus);
  };

  const addItem = (name: string, price: number) => {
    const newItem: BillItem = {
      id: Math.random().toString(36).substring(2, 9),
      name,
      price,
      assignedPersonIds: people.length > 0 ? [people[0].id] : []
    };
    setItems([...items, newItem]);
  };

  const updateItem = (updatedItem: BillItem) => {
    setItems(items.map(item => item.id === updatedItem.id ? updatedItem : item));
  };

  const removeItem = (id: string) => {
    setItems(items.filter(item => item.id !== id));
  };

  const finishOnboarding = () => {
    localStorage.setItem('bayad_buddy_onboarded', 'true');
    setShowOnboarding(false);
  };

  const splitResults = useMemo(() => {
    const resultsMap: Record<string, SplitResult> = {};
    people.forEach(p => {
      resultsMap[p.id] = {
        person: p,
        items: [],
        subtotal: 0,
        total: 0,
        isPaid: !!paidStatus[p.id]
      };
    });

    items.forEach(item => {
      const numPeople = item.assignedPersonIds.length;
      if (numPeople === 0) return;

      const share = item.price / numPeople;

      item.assignedPersonIds.forEach(pid => {
        if (resultsMap[pid]) {
          resultsMap[pid].items.push({ itemName: item.name, share });
          resultsMap[pid].subtotal += share;
          resultsMap[pid].total += share;
        }
      });
    });

    return Object.values(resultsMap);
  }, [people, items, paidStatus]);

  return (
    <div className="min-h-screen bg-slate-50 dark:bg-slate-950 transition-colors duration-300 pb-20">
      {showOnboarding && <Onboarding onFinish={finishOnboarding} />}
      {showChairs && <MusicalChairs people={people} onClose={() => setShowChairs(false)} />}
      {showProfile && (
        <ProfileModal 
          profile={userProfile} 
          onSave={(p) => { setUserProfile(p); setShowProfile(false); }} 
          onClose={() => setShowProfile(false)} 
        />
      )}

      <Header 
        onToggleHistory={() => setShowHistory(!showHistory)} 
        onToggleTheme={toggleTheme}
        onOpenProfile={() => setShowProfile(true)}
        darkMode={darkMode}
        isHistoryVisible={showHistory}
        profileName={userProfile.name}
      />

      <main className="max-w-4xl mx-auto px-4 pt-6 space-y-8">
        {showHistory ? (
          <SavedBills 
            history={history} 
            onClose={() => setShowHistory(false)} 
            onTogglePaid={togglePaidInHistory}
            onRemoveBill={removeBillFromHistory}
            onViewBill={(entry) => setViewingHistoryEntry(entry)}
            onClearHistory={() => {
              if (window.confirm("Remove all saved bills from history?")) {
                setHistory([]);
                localStorage.removeItem('splitwise_history');
              }
            }}
          />
        ) : (
          <>
            <section className="relative">
              <PeopleManager 
                people={people} 
                onAdd={addPerson} 
                onRemove={removePerson} 
              />
              <button 
                onClick={() => setShowChairs(true)}
                className="absolute top-4 right-4 bg-indigo-100 dark:bg-indigo-900/30 text-indigo-700 dark:text-indigo-400 px-3 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest flex items-center gap-2 hover:bg-indigo-200 dark:hover:bg-indigo-900/50 transition-colors shadow-sm"
              >
                <i className="fa-solid fa-chair"></i>
                Musical Chairs
              </button>
            </section>

            <section>
              <BillManager 
                items={items} 
                people={people}
                billTitle={billTitle}
                setBillTitle={setBillTitle}
                onAddItem={addItem} 
                onUpdateItem={updateItem}
                onRemoveItem={removeItem}
                onBulkAdd={() => {}} 
                onClearAll={() => setItems([])}
              />
            </section>

            <section>
              <Summary 
                results={splitResults} 
                totalItems={items.length}
                userProfile={userProfile}
                billTitle={billTitle}
                onTogglePaid={togglePersonPaid}
                onSave={() => {
                  saveToHistory(splitResults);
                  alert("Bill saved to history!");
                }}
                onClear={clearCurrent}
              />
            </section>
          </>
        )}
      </main>

      {/* Modal for viewing active split details */}
      {showSplitModal && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
          <div className="bg-white dark:bg-slate-900 w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">
            <div className="flex justify-between items-center p-6 border-b border-slate-100 dark:border-slate-800 bg-white dark:bg-slate-900 sticky top-0 z-10">
              <h2 className="text-xl font-bold text-slate-800 dark:text-slate-100">Split Details</h2>
              <button 
                onClick={() => setShowSplitModal(false)}
                className="w-10 h-10 flex items-center justify-center bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 dark:hover:bg-slate-700 text-slate-500 dark:text-slate-400 rounded-full transition-colors"
              >
                <i className="fa-solid fa-xmark"></i>
              </button>
            </div>
            <div className="overflow-y-auto flex-1 custom-scrollbar">
              <Summary 
                results={splitResults} 
                totalItems={items.length}
                userProfile={userProfile}
                billTitle={billTitle}
                onTogglePaid={togglePersonPaid}
                onSave={() => {
                  saveToHistory(splitResults);
                  alert("Bill saved to history!");
                  setShowSplitModal(false);
                }}
                onClear={clearCurrent}
                isModal
              />
            </div>
          </div>
        </div>
      )}

      {/* Modal for viewing saved bill details from history */}
      {viewingHistoryEntry && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
          <div className="bg-white dark:bg-slate-900 w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">
            <div className="flex justify-between items-center p-6 border-b border-slate-100 dark:border-slate-800 bg-white dark:bg-slate-900 sticky top-0 z-10">
              <div>
                <h2 className="text-xl font-bold text-slate-800 dark:text-slate-100 line-clamp-1">{viewingHistoryEntry.title}</h2>
                <p className="text-[10px] text-slate-400 dark:text-slate-500 font-bold uppercase tracking-widest">{viewingHistoryEntry.date}</p>
              </div>
              <button 
                onClick={() => setViewingHistoryEntry(null)}
                className="w-10 h-10 flex items-center justify-center bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 dark:hover:bg-slate-700 text-slate-500 dark:text-slate-400 rounded-full transition-colors"
              >
                <i className="fa-solid fa-xmark"></i>
              </button>
            </div>
            <div className="overflow-y-auto flex-1 custom-scrollbar">
              <Summary 
                results={viewingHistoryEntry.results} 
                totalItems={viewingHistoryEntry.results.reduce((acc, r) => acc + r.items.length, 0)}
                userProfile={userProfile}
                billTitle={viewingHistoryEntry.title}
                onTogglePaid={(personId) => togglePaidInHistory(viewingHistoryEntry.id, personId)}
                onSave={() => {}} 
                onClear={() => {}} 
                isModal
                isHistoryView
              />
            </div>
          </div>
        </div>
      )}

      {!showHistory && !showSplitModal && !viewingHistoryEntry && (
        <div className="fixed bottom-0 left-0 right-0 bg-white dark:bg-slate-900 border-t border-slate-200 dark:border-slate-800 p-4 md:hidden flex justify-between items-center shadow-lg z-50 transition-colors">
          <div className="text-sm font-medium text-slate-500 dark:text-slate-400">
            Total: <span className="text-indigo-600 dark:text-indigo-400 font-bold">₱{splitResults.reduce((acc, r) => acc + r.total, 0).toLocaleString(undefined, { minimumFractionDigits: 2 })}</span>
          </div>
          <button 
            onClick={() => setShowSplitModal(true)}
            className="bg-indigo-600 dark:bg-indigo-500 text-white px-6 py-2.5 rounded-full text-sm font-bold shadow-lg shadow-indigo-100 dark:shadow-none active:scale-95 transition-transform flex items-center gap-2"
          >
            <i className="fa-solid fa-expand text-xs"></i>
            View Split
          </button>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useRef } from 'react';
import { SplitResult, UserProfile } from '../types';
import * as htmlToImage from 'html-to-image';

interface Props {
  results: SplitResult[];
  totalItems: number;
  userProfile?: UserProfile;
  billTitle?: string;
  onTogglePaid: (personId: string) => void;
  onSave: () => void;
  onClear: () => void;
  isModal?: boolean;
  isHistoryView?: boolean;
}

const Summary: React.FC<Props> = ({ 
  results, 
  totalItems, 
  userProfile,
  billTitle,
  onTogglePaid, 
  onSave, 
  onClear, 
  isModal = false,
  isHistoryView = false
}) => {
  const exportRef = useRef<HTMLDivElement>(null);
  const activeResults = results.filter(res => res.total > 0);
  const grandTotal = results.reduce((acc, r) => acc + r.total, 0);
  const totalPaid = activeResults.filter(r => r.isPaid).length;
  const isFullyPaid = activeResults.length > 0 && totalPaid === activeResults.length;
  const isPartiallyPaid = totalPaid > 0 && totalPaid < activeResults.length;

  const handleExportImage = async () => {
    if (!exportRef.current) return;

    try {
      const dataUrl = await htmlToImage.toPng(exportRef.current, {
        quality: 1,
        backgroundColor: document.documentElement.classList.contains('dark') ? '#020617' : '#f8fafc',
        pixelRatio: 2,
        skipFonts: true
      });

      const link = document.createElement('a');
      link.download = `bayad-buddy-${new Date().getTime()}.png`;
      link.href = dataUrl;
      link.click();
    } catch (err) {
      console.error('Failed to export image', err);
      alert('Could not generate image. Please try taking a screenshot instead.');
    }
  };

  const handleShare = async () => {
    if (!exportRef.current) return;

    try {
      const dataUrl = await htmlToImage.toPng(exportRef.current, {
        backgroundColor: document.documentElement.classList.contains('dark') ? '#020617' : '#f8fafc',
        pixelRatio: 2,
        skipFonts: true
      });

      const response = await fetch(dataUrl);
      const blob = await response.blob();
      const file = new File([blob], 'bayad-buddy.png', { type: 'image/png' });

      let shareText = `Bill Breakdown from Bayad Buddy: ₱${grandTotal.toLocaleString()}\n`;
      if (userProfile?.paymentMethod === 'Bank') {
        shareText += `Pay to: ${userProfile.name} via ${userProfile.bankName} (${userProfile.accountNumber})`;
      } else if (userProfile?.paymentDetails) {
        shareText += `Pay to: ${userProfile.name} via ${userProfile.paymentMethod} (${userProfile.paymentDetails})`;
      }

      if (navigator.share && navigator.canShare && navigator.canShare({ files: [file] })) {
        await navigator.share({
          files: [file],
          title: 'Bayad Buddy Split Overview',
          text: shareText
        });
      } else {
        handleExportImage();
      }
    } catch (err) {
      console.error('Share failed', err);
      handleExportImage();
    }
  };

  if (activeResults.length === 0) {
    return (
      <div className={`${isModal ? '' : 'bg-white dark:bg-slate-900 rounded-2xl border border-slate-100 dark:border-slate-800 shadow-sm'} p-6 text-center py-12 text-slate-400 italic transition-colors`}>
        Add items and assign them to see the split!
      </div>
    );
  }

  const statusClasses = isFullyPaid 
    ? 'bg-emerald-600 shadow-emerald-200 dark:shadow-none' 
    : isPartiallyPaid 
      ? 'bg-amber-500 shadow-amber-200 dark:shadow-none' 
      : 'bg-slate-900 dark:bg-slate-800 shadow-slate-200 dark:shadow-none';

  const hasPaymentDetails = userProfile?.paymentMethod === 'Bank' 
    ? (userProfile.bankName && userProfile.accountNumber) 
    : userProfile?.paymentDetails;

  return (
    <div className={`${isModal ? '' : 'bg-white dark:bg-slate-900 rounded-2xl border border-slate-100 dark:border-slate-800 shadow-sm'} p-6 transition-colors`}>
      <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between mb-8 gap-4">
        {!isModal && (
          <div className="flex items-center gap-2">
            <i className="fa-solid fa-chart-pie text-indigo-500"></i>
            <h2 className="text-lg font-semibold text-slate-800 dark:text-slate-100">Split Overview</h2>
          </div>
        )}
        <div className="flex flex-wrap gap-2 w-full sm:w-auto">
          {!isModal && !isHistoryView && (
            <button 
              onClick={onClear}
              className="text-xs font-bold text-slate-400 hover:text-rose-500 px-3 py-2 transition-colors"
            >
              Clear All
            </button>
          )}
          <button 
            onClick={handleShare}
            className="flex-1 sm:flex-none bg-indigo-50 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-400 hover:bg-indigo-100 dark:hover:bg-indigo-900/50 px-4 py-2 rounded-xl text-xs font-bold transition-all flex items-center justify-center gap-2"
          >
            <i className="fa-solid fa-share-nodes"></i>
            Share Breakdown
          </button>
          {!isHistoryView && (
            <button 
              onClick={onSave}
              className="flex-1 sm:flex-none bg-emerald-50 dark:bg-emerald-900/30 text-emerald-600 dark:text-emerald-400 hover:bg-emerald-100 dark:hover:bg-emerald-900/50 px-4 py-2 rounded-xl text-xs font-bold transition-all flex items-center justify-center gap-2"
            >
              <i className="fa-solid fa-check"></i>
              Save Split
            </button>
          )}
        </div>
      </div>

      <div ref={exportRef} className="p-4 rounded-3xl dark:bg-slate-950">
        <div className={`mb-8 p-6 text-white rounded-[2rem] shadow-xl transition-all duration-500 overflow-hidden relative ${statusClasses}`}>
          <div className="absolute top-0 right-0 w-32 h-32 bg-white/10 rounded-full blur-3xl -mr-16 -mt-16"></div>

          <div className="flex justify-between items-center mb-6 relative z-10">
            <div className="flex-1 pr-4">
              <span className="text-white/60 text-sm font-black uppercase tracking-[0.15em] block mb-1">
                {billTitle ? billTitle : 'Total Bill'}
              </span>
              <p className="text-4xl font-black">₱{grandTotal.toLocaleString(undefined, { minimumFractionDigits: 2 })}</p>
            </div>
            <div className="text-right">
              <span className="bg-white/20 text-white px-3 py-1 rounded-full text-[10px] font-black border border-white/20 uppercase tracking-wider">
                {isFullyPaid ? 'ALL PAID' : isPartiallyPaid ? `${totalPaid}/${activeResults.length} PAID` : 'UNPAID'}
              </span>
            </div>
          </div>
          <div className="flex justify-between items-end relative z-10">
            <p className="text-white/70 text-xs font-medium italic">
              Breakdown for {activeResults.length} people
            </p>
            <i className={`fa-solid ${isFullyPaid ? 'fa-circle-check' : 'fa-receipt'} text-3xl text-white/30`}></i>
          </div>
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
          {activeResults.map((res) => (
            <div 
              key={res.person.id} 
              className={`text-left bg-white dark:bg-slate-900 rounded-3xl border overflow-hidden flex flex-col shadow-sm border-b-4 transition-all duration-300 ${res.isPaid ? 'opacity-70 grayscale-[0.3]' : 'opacity-100'}`} 
              style={{ borderColor: res.isPaid ? '#10b981' : (AVATAR_COLORS_HEX[res.person.avatarColor] || '#cbd5e1') }}
            >
              <div className="p-5">
                <div className="flex items-center justify-between mb-4">
                  <div className="flex items-center gap-3">
                    <div className={`w-10 h-10 rounded-2xl ${res.isPaid ? 'bg-emerald-500' : res.person.avatarColor} flex items-center justify-center text-white font-bold shadow-lg shadow-current/20 transition-colors`}>
                      {res.isPaid ? <i className="fa-solid fa-check text-xs"></i> : res.person.name.charAt(0).toUpperCase()}
                    </div>
                    <div>
                      <h3 className={`font-black text-sm leading-tight transition-colors ${res.isPaid ? 'text-emerald-600 dark:text-emerald-400' : 'text-slate-800 dark:text-slate-100'}`}>
                        {res.person.name}
                      </h3>
                      <p className={`text-[9px] font-black uppercase tracking-[0.1em] mt-0.5 ${res.isPaid ? 'text-emerald-500/60' : 'text-slate-400 dark:text-slate-500'}`}>
                        {res.isPaid ? 'Has Paid' : 'Owes'}
                      </p>
                    </div>
                  </div>
                  <div className="text-right">
                    <p className={`text-lg font-black transition-colors ${res.isPaid ? 'text-emerald-600 dark:text-emerald-400' : 'text-indigo-600 dark:text-indigo-400'}`}>
                      ₱{res.total.toLocaleString(undefined, { minimumFractionDigits: 2 })}
                    </p>
                  </div>
                </div>

                <div className="space-y-1.5 border-t border-slate-50 dark:border-slate-800 pt-3 mt-3">
                  {res.items.map((item, idx) => (
                    <div key={idx} className="flex justify-between text-[11px] text-slate-500 dark:text-slate-400 font-medium">
                      <span className="truncate flex-1 pr-2">{item.itemName}</span>
                      <span className={`${res.isPaid ? 'text-emerald-500' : 'text-slate-700 dark:text-slate-200'}`}>
                        ₱{item.share.toLocaleString(undefined, { minimumFractionDigits: 2 })}
                      </span>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          ))}
        </div>

        {/* Payment Info Section in Shared Breakdown */}
        {hasPaymentDetails && (
          <div className="mt-8 p-6 bg-slate-50 dark:bg-slate-900/50 rounded-[2rem] border-2 border-dashed border-indigo-100 dark:border-indigo-900/30">
            <div className="flex items-center gap-4">
              <div className={`w-12 h-12 rounded-2xl flex items-center justify-center text-white text-xl shadow-lg ${
                userProfile?.paymentMethod === 'GCash' ? 'bg-blue-600' : 
                userProfile?.paymentMethod === 'Maya' ? 'bg-emerald-500' : 
                userProfile?.paymentMethod === 'Bank' ? 'bg-slate-700' : 'bg-indigo-500'
              }`}>
                <i className={`fa-solid ${
                  userProfile?.paymentMethod === 'GCash' ? 'fa-mobile-screen' : 
                  userProfile?.paymentMethod === 'Maya' ? 'fa-wallet' : 
