import React, { useState, useMemo, useEffect } from 'react';
import { Person, BillItem, SplitResult, HistoryEntry, UserProfile } from './types';
import { AVATAR_COLORS } from './constants';
import PeopleManager from './components/PeopleManager';
import BillManager from './components/BillManager';
import Summary from './components/Summary';
import Header from './components/Header';
import SavedBills from './components/SavedBills';
import Onboarding from './components/Onboarding';
import MusicalChairs from './components/Roulette';
import ProfileModal from './components/ProfileModal';

const App: React.FC = () => {
  // User Profile State
  const [userProfile, setUserProfile] = useState<UserProfile>(() => {
    const saved = localStorage.getItem('bayad_buddy_profile');
    return saved ? JSON.parse(saved) : { name: 'Me', paymentMethod: '', paymentDetails: '' };
  });

  const [showProfile, setShowProfile] = useState(false);

  // Initialize state from LocalStorage or defaults
  const [people, setPeople] = useState<Person[]>(() => {
    const saved = localStorage.getItem('splitwise_people');
    if (saved) return JSON.parse(saved);
    const initialName = localStorage.getItem('bayad_buddy_profile') 
      ? JSON.parse(localStorage.getItem('bayad_buddy_profile')!).name 
      : 'Me';
    return [{ id: '1', name: initialName, avatarColor: AVATAR_COLORS[0] }];
  });

  const [items, setItems] = useState<BillItem[]>(() => {
    const saved = localStorage.getItem('splitwise_items');
    return saved ? JSON.parse(saved) : [];
  });

  const [billTitle, setBillTitle] = useState(() => {
    return localStorage.getItem('splitwise_bill_title') || '';
  });

  const [discountType, setDiscountType] = useState<'flat' | 'percent'>(() => {
    return (localStorage.getItem('splitwise_discount_type') as 'flat' | 'percent') || 'flat';
  });

  const [discountValue, setDiscountValue] = useState<number>(() => {
    return Number(localStorage.getItem('splitwise_discount_value')) || 0;
  });

  const [paidStatus, setPaidStatus] = useState<Record<string, boolean>>(() => {
    const saved = localStorage.getItem('splitwise_paid_status');
    return saved ? JSON.parse(saved) : {};
  });

  const [history, setHistory] = useState<HistoryEntry[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [showSplitModal, setShowSplitModal] = useState(false);
  const [showChairs, setShowChairs] = useState(false);
  const [viewingHistoryEntry, setViewingHistoryEntry] = useState<HistoryEntry | null>(null);
  const [showOnboarding, setShowOnboarding] = useState(() => {
    return localStorage.getItem('bayad_buddy_onboarded') !== 'true';
  });

  const [darkMode, setDarkMode] = useState(() => {
    return localStorage.getItem('splitwise_theme') === 'dark';
  });

  // Sync state to LocalStorage
  useEffect(() => {
    localStorage.setItem('bayad_buddy_profile', JSON.stringify(userProfile));
    setPeople(prev => prev.map((p, i) => i === 0 ? { ...p, name: userProfile.name } : p));
  }, [userProfile]);

  useEffect(() => {
    localStorage.setItem('splitwise_people', JSON.stringify(people));
  }, [people]);

  useEffect(() => {
    localStorage.setItem('splitwise_items', JSON.stringify(items));
  }, [items]);

  useEffect(() => {
    localStorage.setItem('splitwise_bill_title', billTitle);
  }, [billTitle]);

  useEffect(() => {
    localStorage.setItem('splitwise_discount_type', discountType);
  }, [discountType]);

  useEffect(() => {
    localStorage.setItem('splitwise_discount_value', discountValue.toString());
  }, [discountValue]);

  useEffect(() => {
    localStorage.setItem('splitwise_paid_status', JSON.stringify(paidStatus));
  }, [paidStatus]);

  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('splitwise_theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('splitwise_theme', 'light');
    }
  }, [darkMode]);

  useEffect(() => {
    const saved = localStorage.getItem('splitwise_history');
    if (saved) {
      try {
        setHistory(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to load history", e);
      }
    }
  }, []);

  const toggleTheme = () => setDarkMode(!darkMode);

  const togglePersonPaid = (personId: string) => {
    setPaidStatus(prev => ({
      ...prev,
      [personId]: !prev[personId]
    }));
  };

  const togglePaidInHistory = (billId: string, personId: string) => {
    const updatedHistory = history.map(entry => {
      if (entry.id === billId) {
        const updatedEntry = {
          ...entry,
          results: entry.results.map(res => 
            res.person.id === personId ? { ...res, isPaid: !res.isPaid } : res
          )
        };
        if (viewingHistoryEntry?.id === billId) {
          setViewingHistoryEntry(updatedEntry);
        }
        return updatedEntry;
      }
      return entry;
    });
    setHistory(updatedHistory);
    localStorage.setItem('splitwise_history', JSON.stringify(updatedHistory));
  };

  const removeBillFromHistory = (billId: string) => {
    const updatedHistory = history.filter(entry => entry.id !== billId);
    setHistory(updatedHistory);
    localStorage.setItem('splitwise_history', JSON.stringify(updatedHistory));
  };

  const saveToHistory = (results: SplitResult[]) => {
    if (items.length === 0) return;
    const generateId = () => {
      try { return crypto.randomUUID(); } 
      catch (e) { return Math.random().toString(36).substring(2, 15) + Date.now().toString(36); }
    };

    const total = results.reduce((acc, r) => acc + r.total, 0);
    const newEntry: HistoryEntry = {
      id: generateId(),
      date: new Date().toLocaleString(),
      title: billTitle.trim() || (items.length > 0 ? items[0].name + (items.length > 1 ? '...' : '') : 'Quick Split'),
      total,
      results: JSON.parse(JSON.stringify(results)) 
    };

    const updatedHistory = [newEntry, ...history];
    setHistory(updatedHistory);
    localStorage.setItem('splitwise_history', JSON.stringify(updatedHistory));
  };

  const clearCurrent = () => {
    if (window.confirm("Clear all items and people?")) {
      setItems([]);
      setBillTitle('');
      setDiscountValue(0);
      setPeople([{ id: '1', name: userProfile.name, avatarColor: AVATAR_COLORS[0] }]);
      setPaidStatus({});
      localStorage.removeItem('splitwise_items');
      localStorage.removeItem('splitwise_bill_title');
      localStorage.removeItem('splitwise_discount_value');
      localStorage.removeItem('splitwise_people');
      localStorage.removeItem('splitwise_paid_status');
    }
  };

  const addPerson = (name: string) => {
    const newPerson: Person = {
      id: Math.random().toString(36).substring(2, 9),
      name,
      avatarColor: AVATAR_COLORS[people.length % AVATAR_COLORS.length]
    };
    setPeople([...people, newPerson]);
  };

  const removePerson = (id: string) => {
    if (people.length <= 1) return;
    setPeople(people.filter(p => p.id !== id));
    setItems(items.map(item => ({
      ...item,
      assignedPersonIds: item.assignedPersonIds.filter(pid => pid !== id)
    })));
    const newPaidStatus = { ...paidStatus };
    delete newPaidStatus[id];
    setPaidStatus(newPaidStatus);
  };

  const addItem = (name: string, price: number) => {
    const newItem: BillItem = {
      id: Math.random().toString(36).substring(2, 9),
      name,
      price,
      assignedPersonIds: people.length > 0 ? [people[0].id] : []
    };
    setItems([...items, newItem]);
  };

  const updateItem = (updatedItem: BillItem) => {
    setItems(items.map(item => item.id === updatedItem.id ? updatedItem : item));
  };

  const removeItem = (id: string) => {
    setItems(items.filter(item => item.id !== id));
  };

  const finishOnboarding = () => {
    localStorage.setItem('bayad_buddy_onboarded', 'true');
    setShowOnboarding(false);
  };

  const splitResults = useMemo(() => {
    const resultsMap: Record<string, SplitResult> = {};
    people.forEach(p => {
      resultsMap[p.id] = {
        person: p,
        items: [],
        subtotal: 0,
        discountAmount: 0,
        total: 0,
        isPaid: !!paidStatus[p.id]
      };
    });

    let globalSubtotal = 0;
    items.forEach(item => {
      const numPeople = item.assignedPersonIds.length;
      if (numPeople === 0) return;
      globalSubtotal += item.price;
      const share = item.price / numPeople;
      item.assignedPersonIds.forEach(pid => {
        if (resultsMap[pid]) {
          resultsMap[pid].items.push({ itemName: item.name, share });
          resultsMap[pid].subtotal += share;
        }
      });
    });

    // Calculate total discount
    const actualDiscount = discountType === 'percent' 
      ? globalSubtotal * (discountValue / 100) 
      : Math.min(discountValue, globalSubtotal);

    // Apply discount proportionally
    if (globalSubtotal > 0 && actualDiscount > 0) {
      Object.values(resultsMap).forEach(res => {
        const propShare = res.subtotal / globalSubtotal;
        res.discountAmount = actualDiscount * propShare;
      });
    }

    // Final Total Calculation
    Object.values(resultsMap).forEach(res => {
      res.total = Math.max(0, res.subtotal - res.discountAmount);
    });

    return Object.values(resultsMap);
  }, [people, items, paidStatus, discountType, discountValue]);

  return (
    <div className="min-h-screen bg-slate-50 dark:bg-slate-950 transition-colors duration-300 pb-20">
      {showOnboarding && <Onboarding onFinish={finishOnboarding} />}
      {showChairs && <MusicalChairs people={people} onClose={() => setShowChairs(false)} />}
      {showProfile && (
        <ProfileModal 
          profile={userProfile} 
          onSave={(p) => { setUserProfile(p); setShowProfile(false); }} 
          onClose={() => setShowProfile(false)} 
        />
      )}

      <Header 
        onToggleHistory={() => setShowHistory(!showHistory)} 
        onToggleTheme={toggleTheme}
        onOpenProfile={() => setShowProfile(true)}
        darkMode={darkMode}
        isHistoryVisible={showHistory}
        profileName={userProfile.name}
      />

      <main className="max-w-4xl mx-auto px-4 pt-6 space-y-8">
        {showHistory ? (
          <SavedBills 
            history={history} 
            onClose={() => setShowHistory(false)} 
            onTogglePaid={togglePaidInHistory}
            onRemoveBill={removeBillFromHistory}
            onViewBill={(entry) => setViewingHistoryEntry(entry)}
            onClearHistory={() => {
              if (window.confirm("Remove all saved bills from history?")) {
                setHistory([]);
                localStorage.removeItem('splitwise_history');
              }
            }}
          />
        ) : (
          <>
            <section className="relative">
              <PeopleManager 
                people={people} 
                onAdd={addPerson} 
                onRemove={removePerson} 
              />
              <button 
                onClick={() => setShowChairs(true)}
                className="absolute top-4 right-4 bg-indigo-100 dark:bg-indigo-900/30 text-indigo-700 dark:text-indigo-400 px-3 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest flex items-center gap-2 hover:bg-indigo-200 dark:hover:bg-indigo-900/50 transition-colors shadow-sm"
              >
                <i className="fa-solid fa-chair"></i>
                Musical Chairs
              </button>
            </section>

            <section>
              <BillManager 
                items={items} 
                people={people}
                billTitle={billTitle}
                setBillTitle={setBillTitle}
                discountType={discountType}
                setDiscountType={setDiscountType}
                discountValue={discountValue}
                setDiscountValue={setDiscountValue}
                onAddItem={addItem} 
                onUpdateItem={updateItem}
                onRemoveItem={removeItem}
                onBulkAdd={() => {}} 
                onClearAll={() => setItems([])}
              />
            </section>

            <section>
              <Summary 
                results={splitResults} 
                totalItems={items.length}
                userProfile={userProfile}
                billTitle={billTitle}
                onTogglePaid={togglePersonPaid}
                onSave={() => {
                  saveToHistory(splitResults);
                  alert("Bill saved!");
                }}
                onClear={clearCurrent}
              />
            </section>
          </>
        )}
      </main>

      {showSplitModal && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
          <div className="bg-white dark:bg-slate-900 w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">
            <div className="flex justify-between items-center p-6 border-b border-slate-100 dark:border-slate-800 bg-white dark:bg-slate-900 sticky top-0 z-10">
              <h2 className="text-xl font-bold text-slate-800 dark:text-slate-100">Split Details</h2>
              <button onClick={() => setShowSplitModal(false)} className="w-10 h-10 flex items-center justify-center bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 dark:hover:bg-slate-700 text-slate-500 dark:text-slate-400 rounded-full transition-colors">
                <i className="fa-solid fa-xmark"></i>
              </button>
            </div>
            <div className="overflow-y-auto flex-1 custom-scrollbar">
              <Summary 
                results={splitResults} 
                totalItems={items.length}
                userProfile={userProfile}
                billTitle={billTitle}
                onTogglePaid={togglePersonPaid}
                onSave={() => {
                  saveToHistory(splitResults);
                  alert("Bill saved!");
                  setShowSplitModal(false);
                }}
                onClear={clearCurrent}
                isModal
              />
            </div>
          </div>
        </div>
      )}

      {viewingHistoryEntry && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
          <div className="bg-white dark:bg-slate-900 w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">
            <div className="flex justify-between items-center p-6 border-b border-slate-100 dark:border-slate-800 bg-white dark:bg-slate-900 sticky top-0 z-10">
              <div>
                <h2 className="text-xl font-bold text-slate-800 dark:text-slate-100 line-clamp-1">{viewingHistoryEntry.title}</h2>
                <p className="text-[10px] text-slate-400 dark:text-slate-500 font-bold uppercase tracking-widest">{viewingHistoryEntry.date}</p>
              </div>
              <button onClick={() => setViewingHistoryEntry(null)} className="w-10 h-10 flex items-center justify-center bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 dark:hover:bg-slate-700 text-slate-500 dark:text-slate-400 rounded-full transition-colors">
                <i className="fa-solid fa-xmark"></i>
              </button>
            </div>
            <div className="overflow-y-auto flex-1 custom-scrollbar">
              <Summary 
                results={viewingHistoryEntry.results} 
                totalItems={viewingHistoryEntry.results.reduce((acc, r) => acc + r.items.length, 0)}
                userProfile={userProfile}
                billTitle={viewingHistoryEntry.title}
                onTogglePaid={(personId) => togglePaidInHistory(viewingHistoryEntry.id, personId)}
                onSave={() => {}} 
                onClear={() => {}} 
                isModal
                isHistoryView
              />
            </div>
          </div>
        </div>
      )}

      {!showHistory && !showSplitModal && !viewingHistoryEntry && (
        <div className="fixed bottom-0 left-0 right-0 bg-white dark:bg-slate-900 border-t border-slate-200 dark:border-slate-800 p-4 md:hidden flex justify-between items-center shadow-lg z-50 transition-colors">
          <div className="text-sm font-medium text-slate-500 dark:text-slate-400">
            Total: <span className="text-indigo-600 dark:text-indigo-400 font-bold">₱{splitResults.reduce((acc, r) => acc + r.total, 0).toLocaleString(undefined, { minimumFractionDigits: 2 })}</span>
          </div>
          <button 
            onClick={() => setShowSplitModal(true)}
            className="bg-indigo-600 dark:bg-indigo-500 text-white px-6 py-2.5 rounded-full text-sm font-bold shadow-lg active:scale-95 transition-transform flex items-center gap-2"
          >
            <i className="fa-solid fa-expand text-xs"></i>
            View Split
          </button>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { BillItem, Person } from '../types';

interface Props {
  items: BillItem[];
  people: Person[];
  billTitle: string;
  setBillTitle: (title: string) => void;
  discountType: 'flat' | 'percent';
  setDiscountType: (type: 'flat' | 'percent') => void;
  discountValue: number;
  setDiscountValue: (value: number) => void;
  onAddItem: (name: string, price: number) => void;
  onUpdateItem: (item: BillItem) => void;
  onRemoveItem: (id: string) => void;
  onBulkAdd: (items: { name: string; price: number }[]) => void;
  onClearAll: () => void;
}

const BillManager: React.FC<Props> = ({ 
  items, 
  people, 
  billTitle,
  setBillTitle,
  discountType,
  setDiscountType,
  discountValue,
  setDiscountValue,
  onAddItem, 
  onUpdateItem, 
  onRemoveItem, 
  onClearAll
}) => {
  const [itemName, setItemName] = useState('');
  const [itemPrice, setItemPrice] = useState('');

  const handleAddItem = (e: React.FormEvent) => {
    e.preventDefault();
    const price = parseFloat(itemPrice);
    if (itemName.trim() && !isNaN(price)) {
      onAddItem(itemName.trim(), price);
      setItemName('');
      setItemPrice('');
    }
  };

  const togglePersonOnItem = (item: BillItem, personId: string) => {
    const isAssigned = item.assignedPersonIds.includes(personId);
    let newIds: string[];
    if (isAssigned) {
      newIds = item.assignedPersonIds.filter(id => id !== personId);
    } else {
      newIds = [...item.assignedPersonIds, personId];
    }
    onUpdateItem({ ...item, assignedPersonIds: newIds });
  };

  const subtotalBill = items.reduce((acc, item) => acc + item.price, 0);
  const actualDiscount = discountType === 'percent' 
    ? subtotalBill * (discountValue / 100) 
    : Math.min(discountValue, subtotalBill);
  const totalBill = Math.max(0, subtotalBill - actualDiscount);

  return (
    <div className="bg-white dark:bg-slate-900 rounded-3xl p-6 shadow-sm border border-slate-100 dark:border-slate-800 transition-colors relative overflow-hidden">
      {/* Header */}
      <div className="flex items-center justify-between mb-8">
        <div>
          <h2 className="text-xl font-black text-slate-800 dark:text-slate-100 tracking-tight">Bill Content</h2>
          <p className="text-[10px] font-black uppercase tracking-widest text-slate-400 mt-1">Assign items to people</p>
        </div>
      </div>

      <div className="space-y-6">
        {/* Bill Metadata */}
        <div className="bg-slate-50 dark:bg-slate-800/40 p-5 rounded-2xl border-2 border-slate-100 dark:border-slate-800 transition-all focus-within:border-indigo-500/30">
          <label className="text-[10px] font-black uppercase tracking-widest text-indigo-500 dark:text-indigo-400 mb-2 block">What are we splitting?</label>
          <div className="relative">
            <div className="absolute inset-y-0 left-0 flex items-center pointer-events-none">
              <i className="fa-solid fa-file-invoice-dollar text-slate-400"></i>
            </div>
            <input 
              type="text"
              value={billTitle}
              onChange={(e) => setBillTitle(e.target.value)}
              placeholder="e.g. Dinner at Mary's Cafe"
              className="w-full bg-transparent border-none rounded-none pl-7 py-1 text-xl font-bold focus:ring-0 outline-none text-slate-900 dark:text-slate-50 placeholder-slate-300 dark:placeholder-slate-600 transition-all"
            />
          </div>
        </div>

        {/* Manual Item Entry */}
        <form onSubmit={handleAddItem} className="space-y-3">
          <div className="flex flex-col sm:flex-row gap-3">
            <div className="flex-[2] relative group">
              <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                <i className="fa-solid fa-utensils text-slate-400 group-focus-within:text-indigo-500 transition-colors"></i>
              </div>
              <input 
                type="text" 
                value={itemName}
                onChange={(e) => setItemName(e.target.value)}
                placeholder="Item name (e.g. Burger)"
                className="w-full bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-xl pl-11 pr-4 py-3 text-sm focus:ring-2 focus:ring-indigo-500 outline-none text-slate-900 dark:text-slate-50 placeholder-slate-400"
              />
            </div>
            <div className="flex-1 relative group">
              <span className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 text-sm font-bold">₱</span>
              <input 
                type="number" 
                step="0.01"
                value={itemPrice}
                onChange={(e) => setItemPrice(e.target.value)}
                placeholder="0.00"
                className="w-full bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-xl pl-8 pr-4 py-3 text-sm font-bold focus:ring-2 focus:ring-indigo-500 outline-none text-slate-900 dark:text-slate-50 placeholder-slate-400"
              />
            </div>
            <button 
              type="submit"
              disabled={!itemName.trim() || !itemPrice}
              className="bg-slate-900 dark:bg-slate-50 text-white dark:text-slate-950 px-8 py-3 rounded-xl text-sm font-black hover:opacity-90 disabled:opacity-30 transition-all active:scale-95"
            >
              Add
            </button>
          </div>
        </form>

        {/* Discount Section */}
        <div className="bg-indigo-50/50 dark:bg-indigo-900/10 p-5 rounded-2xl border border-indigo-100 dark:border-indigo-900/30 transition-all">
          <div className="flex items-center justify-between mb-3">
             <label className="text-[10px] font-black uppercase tracking-widest text-indigo-600 dark:text-indigo-400">Add Discount</label>
             <div className="flex bg-white dark:bg-slate-800 p-1 rounded-lg border border-slate-200 dark:border-slate-700 shadow-sm">
                <button 
                  onClick={() => setDiscountType('flat')}
                  className={`px-3 py-1 text-[10px] font-black rounded-md transition-all ${discountType === 'flat' ? 'bg-indigo-600 text-white' : 'text-slate-400'}`}
                >₱</button>
                <button 
                  onClick={() => setDiscountType('percent')}
                  className={`px-3 py-1 text-[10px] font-black rounded-md transition-all ${discountType === 'percent' ? 'bg-indigo-600 text-white' : 'text-slate-400'}`}
                >%</button>
             </div>
          </div>
          <div className="relative group">
            <span className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 text-sm font-bold">
              {discountType === 'flat' ? '₱' : '%'}
            </span>
            <input 
              type="number"
              value={discountValue || ''}
              onChange={(e) => setDiscountValue(Number(e.target.value))}
              placeholder="0"
              className="w-full bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-xl pl-8 pr-4 py-3 text-sm font-bold focus:ring-2 focus:ring-indigo-500 outline-none text-slate-900 dark:text-slate-50 placeholder-slate-400"
            />
          </div>
        </div>

        {/* Items List */}
        <div className="mt-8">
          <div className="flex items-center justify-between mb-4 px-1">
            <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Itemized List ({items.length})</h3>
            {items.length > 0 && (
              <button 
                onClick={onClearAll}
                className="text-[10px] font-black text-rose-500 uppercase tracking-widest hover:bg-rose-50 dark:hover:bg-rose-900/10 px-2 py-1 rounded"
              >
                Reset All
              </button>
            )}
          </div>

          <div className="space-y-3 max-h-[450px] overflow-y-auto custom-scrollbar pr-1">
            {items.length === 0 ? (
              <div className="text-center py-16 rounded-3xl border-2 border-dashed border-slate-100 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-800/20">
                <i className="fa-solid fa-receipt text-slate-200 dark:text-slate-700 text-4xl mb-3"></i>
                <p className="text-slate-400 dark:text-slate-500 text-sm font-medium">No items added yet</p>
              </div>
            ) : (
              items.map((item) => (
                <div key={item.id} className="p-4 bg-white dark:bg-slate-900 rounded-2xl border border-slate-100 dark:border-slate-800 group transition-all hover:shadow-lg hover:border-indigo-100 dark:hover:border-indigo-900 relative">
                  <div className="flex justify-between items-start mb-3">
                    <div className="flex-1">
                      <h3 className="font-bold text-slate-800 dark:text-slate-200">{item.name}</h3>
                      <p className="text-indigo-600 dark:text-indigo-400 font-black text-sm">₱{item.price.toLocaleString(undefined, { minimumFractionDigits: 2 })}</p>
                    </div>
                    <button 
                      onClick={() => onRemoveItem(item.id)}
                      className="w-8 h-8 flex items-center justify-center rounded-full text-slate-300 hover:bg-rose-50 hover:text-rose-500 transition-all opacity-0 group-hover:opacity-100"
                    >
                      <i className="fa-solid fa-trash-can text-xs"></i>
                    </button>
                  </div>

                  <div className="flex flex-wrap gap-2 mt-2">
                    {people.map((person) => {
                      const active = item.assignedPersonIds.includes(person.id);
                      return (
                        <button
                          key={person.id}
                          onClick={() => togglePersonOnItem(item, person.id)}
                          className={`
                            flex items-center gap-1.5 px-3 py-2 rounded-full text-[10px] font-bold border transition-all active:scale-95
                            ${active 
                              ? `${person.avatarColor.replace('bg-', 'text-')} bg-white dark:bg-slate-900 border-current shadow-sm` 
                              : 'bg-slate-50 dark:bg-slate-800/50 text-slate-400 dark:text-slate-600 border-transparent'
                            }
                          `}
                        >
                          <div className={`w-3.5 h-3.5 rounded-full ${person.avatarColor} flex items-center justify-center text-[7px] text-white shadow-inner`}>
                            {person.name.charAt(0)}
                          </div>
                          {person.name}
                        </button>
                      );
                    })}
                  </div>
                </div>
              ))
            )}
          </div>
        </div>

        {items.length > 0 && (
          <div className="mt-8 pt-6 border-t border-slate-100 dark:border-slate-800 flex justify-between items-center px-2">
            <div>
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Grand Total</p>
              <p className="text-indigo-600 dark:text-indigo-400 text-3xl font-black">₱{totalBill.toLocaleString(undefined, { minimumFractionDigits: 2 })}</p>
              {actualDiscount > 0 && (
                <p className="text-[10px] font-bold text-emerald-500 uppercase tracking-widest mt-1 italic">
                  Saved ₱{actualDiscount.toLocaleString(undefined, { minimumFractionDigits: 2 })}
