              <div className="flex gap-1 overflow-x-auto pb-1 custom-scrollbar">
                <button
                  onClick={() => setDiscountTarget('everyone')}
                  className={`px-3 py-2 rounded-xl text-[10px] font-black whitespace-nowrap border transition-all ${
                    discountTarget === 'everyone' 
                      ? 'bg-indigo-600 border-transparent text-white shadow-md' 
                      : 'bg-white dark:bg-slate-900 border-slate-200 dark:border-slate-700 text-slate-400'
                  }`}
                >
                  Everyone
                </button>
                {people.map(person => (
                  <button
                    key={person.id}
                    onClick={() => setDiscountTarget(person.id)}
                    className={`px-3 py-2 rounded-xl text-[10px] font-black whitespace-nowrap border transition-all flex items-center gap-2 ${
                      discountTarget === person.id 
                        ? `${person.avatarColor} border-transparent text-white shadow-md` 
                        : 'bg-white dark:bg-slate-900 border-slate-200 dark:border-slate-700 text-slate-400'
                    }`}
                  >
                    <div className={`w-3 h-3 rounded-full flex items-center justify-center text-[6px] text-white ${discountTarget === person.id ? 'bg-white/30' : person.avatarColor}`}>
                      {person.name.charAt(0)}
